// NURS 1000 Exam 4 — Infection Control, Hygiene & Communication (180 Questions)
const S={IC:"Infection Control & Hygiene",SB:"SBAR & Communication"};
const R=[
// ——— INFECTION CONTROL & HYGIENE (Questions 1–130) ———
// --- General Knowledge (1–30) ---
{id:1,s:"IC",t:"mc",q:"What are the six links in the chain of infection in correct order?",o:["Infectious agent, reservoir, portal of exit, mode of transmission, portal of entry, susceptible host","Reservoir, infectious agent, portal of entry, portal of exit, mode of transmission, susceptible host","Susceptible host, infectious agent, reservoir, portal of exit, portal of entry, mode of transmission","Infectious agent, portal of exit, reservoir, susceptible host, mode of transmission, portal of entry"],c:[0],e:"The chain of infection follows: Infectious agent → Reservoir → Portal of exit → Mode of transmission → Portal of entry → Susceptible host. Remember the mnemonic 'I Rest My Peanut Butter Sandwich' to recall the order.",a:"A) Infectious agent, reservoir, portal of exit, mode of transmission, portal of entry, susceptible host",r:"Chain of Infection"},
{id:2,s:"IC",t:"mc",q:"Which mnemonic helps remember the six links in the chain of infection?",o:["'I Rest My Peanut Butter Sandwich'","'Patients Really Must Practice Better Safety'","'Infections Run Many Paths Before Stopping'","'I Remember My Patient's Best Symptoms'"],c:[0],e:"'I Rest My Peanut Butter Sandwich' stands for Infectious agent, Reservoir, Mode of transmission, Portal of exit, Portal of entry (Butter = entry), and Susceptible host (Sandwich). This is the standard mnemonic for the chain of infection.",a:"A) 'I Rest My Peanut Butter Sandwich'",r:"Chain of Infection"},
{id:3,s:"IC",t:"mc",q:"Breaking any single link in the chain of infection will:",o:["Only slow the spread of infection","Prevent infection from occurring","Require additional links to be broken","Have no effect on disease transmission"],c:[1],e:"The chain of infection requires all six links to be intact for disease transmission. Breaking any single link — such as proper hand hygiene (mode of transmission) or vaccination (susceptible host) — will prevent the infection from spreading.",a:"B) Prevent infection from occurring",r:"Chain of Infection"},
{id:4,s:"IC",t:"mc",q:"In the chain of infection, which link does a human carrier with hepatitis B represent?",o:["Infectious agent","Reservoir","Portal of exit","Susceptible host"],c:[1],e:"A reservoir is the place where a pathogen lives and multiplies. A human carrier with hepatitis B serves as the reservoir because the virus resides within them, even if they show no symptoms. The infectious agent itself is the hepatitis B virus.",a:"B) Reservoir",r:"Chain of Infection"},
{id:5,s:"IC",t:"mc",q:"Which of the following is an example of a portal of exit?",o:["A needlestick injury","The respiratory tract of an infected patient","An open wound on a susceptible person","A contaminated blood pressure cuff"],c:[1],e:"A portal of exit is the path by which a pathogen leaves the reservoir. The respiratory tract of an infected person allows pathogens to exit through coughing or sneezing. An open wound on a susceptible person would be a portal of entry, not exit.",a:"B) The respiratory tract of an infected patient",r:"Chain of Infection"},
{id:6,s:"IC",t:"mc",q:"Standard Precautions are used for:",o:["Only patients with confirmed infections","Patients with bloodborne pathogen exposure","All patients regardless of diagnosis","Only immunocompromised patients"],c:[2],e:"Standard Precautions are the foundation of infection prevention and are applied to ALL patients regardless of their suspected or confirmed infection status. They include hand hygiene, PPE use, respiratory hygiene, and safe injection practices.",a:"C) All patients regardless of diagnosis",r:"Standard Precautions"},
{id:7,s:"IC",t:"mc",q:"Which type of transmission involves large respiratory droplets that travel less than 3 feet?",o:["Airborne transmission","Contact transmission","Droplet transmission","Vector-borne transmission"],c:[2],e:"Droplet transmission involves large respiratory droplets (>5 microns) that travel short distances, typically less than 3 feet, before falling due to gravity. This is different from airborne transmission, where smaller particles remain suspended in the air for longer periods.",a:"C) Droplet transmission",r:"Modes of Transmission"},
{id:8,s:"IC",t:"mc",q:"Which precaution type requires a negative pressure room and an N95 respirator?",o:["Standard Precautions","Contact Precautions","Droplet Precautions","Airborne Precautions"],c:[3],e:"Airborne Precautions require a negative pressure (airborne infection isolation) room and an N95 respirator or PAPR. These measures are needed because airborne pathogens remain suspended in the air and can travel long distances. Remember 'MTV' — Measles, TB, Varicella require airborne precautions.",a:"D) Airborne Precautions",r:"Transmission-Based Precautions"},
{id:9,s:"IC",t:"mc",q:"The mnemonic 'MTV' helps nurses remember which diseases require airborne precautions. What does MTV stand for?",o:["MRSA, Tuberculosis, Vancomycin-resistant enterococcus","Measles, Tuberculosis, Varicella","Meningitis, Tetanus, Viral hepatitis","Mumps, Tuberculosis, Varicella"],c:[1],e:"MTV stands for Measles, Tuberculosis, and Varicella (chickenpox). These three diseases require airborne precautions including a negative pressure room and N95 respirator because their pathogens remain suspended in the air and can travel long distances.",a:"B) Measles, Tuberculosis, Varicella",r:"Airborne Precautions"},
{id:10,s:"IC",t:"mc",q:"A patient is diagnosed with C. difficile infection. Which hand hygiene method is required?",o:["Alcohol-based hand rub for 20 seconds","Soap and water only","Either alcohol-based rub or soap and water","Hand hygiene is not needed if gloves were worn"],c:[1],e:"C. difficile produces spores that are NOT killed by alcohol-based hand sanitizers. Soap and water with friction is required to physically remove the spores. Remember: 'SOAP it up' — Soap and water ONLY for C. diff, not alcohol.",a:"B) Soap and water only",r:"Hand Hygiene"},
{id:11,s:"IC",t:"tf",q:"True or False: Alcohol-based hand sanitizer is effective against C. difficile spores.",o:["True","False"],c:[1],e:"False. C. difficile forms spores that are resistant to alcohol-based hand sanitizers. Soap and water with mechanical friction is the only effective hand hygiene method for C. diff. Remember the mnemonic 'SOAP it up' for C. diff care.",a:"B) False",r:"Hand Hygiene"},
{id:12,s:"IC",t:"mc",q:"According to the WHO, how many moments of hand hygiene are there?",o:["3","4","5","6"],c:[2],e:"The WHO identifies 5 moments of hand hygiene: (1) before patient contact, (2) before an aseptic task, (3) after body fluid exposure, (4) after patient contact, and (5) after touching patient surroundings. These moments provide a framework for hand hygiene compliance.",a:"C) 5",r:"Hand Hygiene"},
{id:13,s:"IC",t:"sata",q:"Which of the following are included in the WHO's 5 Moments of Hand Hygiene? (Select all that apply)",o:["Before patient contact","After removing gloves only","Before an aseptic task","After body fluid exposure risk","After touching patient surroundings"],c:[0,2,3,4],e:"The 5 Moments are: before patient contact, before an aseptic task, after body fluid exposure risk, after patient contact, and after touching patient surroundings. Hand hygiene is required after patient contact (not just after removing gloves).",a:"A, C, D, E",r:"Hand Hygiene"},
{id:14,s:"IC",t:"mc",q:"How long should alcohol-based hand rub be applied?",o:["10 seconds","15 seconds","20 seconds","30 seconds"],c:[2],e:"Alcohol-based hand rub should be applied for at least 20 seconds, rubbing all surfaces of the hands until dry. The friction and drying time are essential for the alcohol to effectively kill microorganisms on the skin.",a:"C) 20 seconds",r:"Hand Hygiene"},
{id:15,s:"IC",t:"mc",q:"When should a nurse use soap and water instead of alcohol-based hand rub?",o:["Before every patient contact","When hands are visibly soiled or when caring for a patient with C. difficile","Only when entering an isolation room","After removing sterile gloves"],c:[1],e:"Soap and water should be used when hands are visibly soiled or contaminated with blood/body fluids, and when caring for patients with C. difficile or other spore-forming organisms. Alcohol does not remove visible soil or kill spores.",a:"B) When hands are visibly soiled or when caring for a patient with C. difficile",r:"Hand Hygiene"},
{id:16,s:"IC",t:"order",q:"Place the steps of PPE donning (putting on) in the correct order.",o:["Perform hand hygiene","Apply gown","Put on mask or N95 respirator","Apply eye protection","Put on gloves"],c:[0,1,2,3,4],e:"The correct donning order is: Hand hygiene → Gown → Mask/N95 → Eye protection → Gloves. Remember: 'My Gown Goes on, Eyes Covered, Gloves Last.' Gloves go on last so they cover the gown cuffs and create a complete barrier.",a:"Hand hygiene → Gown → Mask/N95 → Eye protection → Gloves",r:"PPE Donning"},
{id:17,s:"IC",t:"order",q:"Place the steps of PPE doffing (removal) in the correct order.",o:["Remove gloves","Remove eye protection","Remove gown","Remove mask","Perform hand hygiene"],c:[0,1,2,3,4],e:"The correct doffing order is: Gloves → Eye protection → Gown → Mask → Hand hygiene. Remember: 'Gloves Go, Eyes Off, Gown Down, Mask Last, Sanitize.' Gloves are the most contaminated item and are removed first.",a:"Gloves → Eye protection → Gown → Mask → Hand hygiene",r:"PPE Doffing"},
{id:18,s:"IC",t:"mc",q:"During PPE donning, which item is applied LAST?",o:["Gown","Mask","Eye protection","Gloves"],c:[3],e:"Gloves are applied last during donning so they can overlap the gown cuffs and create a continuous barrier. The full donning order is: hand hygiene, gown, mask/N95, eye protection, then gloves.",a:"D) Gloves",r:"PPE Donning"},
{id:19,s:"IC",t:"mc",q:"During PPE doffing, which item is removed FIRST?",o:["Mask","Gown","Gloves","Eye protection"],c:[2],e:"Gloves are removed first during doffing because they are the most contaminated item. The doffing order is: gloves, eye protection, gown, mask, then hand hygiene. Remember: 'Gloves Go, Eyes Off, Gown Down, Mask Last, Sanitize.'",a:"C) Gloves",r:"PPE Doffing"},
{id:20,s:"IC",t:"mc",q:"What is the difference between medical asepsis and surgical asepsis?",o:["Medical asepsis eliminates all organisms; surgical asepsis reduces organisms","Medical asepsis reduces organisms (clean technique); surgical asepsis eliminates all organisms (sterile technique)","They are the same concept","Medical asepsis is used in surgery; surgical asepsis is used in medical units"],c:[1],e:"Medical asepsis (clean technique) reduces the number and transfer of pathogens through practices like hand hygiene. Surgical asepsis (sterile technique) eliminates ALL microorganisms, including spores, and is used for invasive procedures like surgery and catheter insertion.",a:"B) Medical asepsis reduces organisms (clean technique); surgical asepsis eliminates all organisms (sterile technique)",r:"Asepsis"},
{id:21,s:"IC",t:"tf",q:"True or False: A 1-inch border around the edge of a sterile field is considered contaminated.",o:["True","False"],c:[0],e:"True. The outer 1-inch border of a sterile field is considered contaminated because it is in contact with or close to non-sterile surfaces. Only items placed within the center of the field are considered sterile.",a:"A) True",r:"Sterile Technique"},
{id:22,s:"IC",t:"mc",q:"A nurse turns their back on a sterile field to answer the phone. What should the nurse do?",o:["Continue the procedure since the field was only unattended briefly","Consider the field contaminated and set up a new one","Have another nurse verify the field is still sterile","Cover the field with a sterile drape and continue"],c:[1],e:"Once a nurse turns their back on a sterile field, it is considered contaminated because the nurse can no longer verify that nothing unsterile has come in contact with it. A new sterile field must be set up. Never turn your back on a sterile field.",a:"B) Consider the field contaminated and set up a new one",r:"Sterile Technique"},
{id:23,s:"IC",t:"mc",q:"Which of the following would contaminate a sterile field?",o:["Placing a sterile item in the center of the field","Keeping the field at waist level or above","Spilling sterile saline onto the sterile drape","Using sterile forceps to arrange items on the field"],c:[2],e:"Moisture on a sterile field creates a pathway for microorganisms to travel from non-sterile surfaces beneath the drape to the sterile field (strike-through contamination). A sterile field must be kept dry at all times.",a:"C) Spilling sterile saline onto the sterile drape",r:"Sterile Technique"},
{id:24,s:"IC",t:"mc",q:"HAIs stands for:",o:["Hospital-Acquired Immunodeficiencies","Healthcare-Associated Infections","High-Acuity Illnesses","Hospitalization-Acquired Inflammations"],c:[1],e:"HAIs are Healthcare-Associated Infections — infections that patients acquire during the course of receiving healthcare treatment. Common HAIs include CAUTI, CLABSI, SSI, and VAP. They are a significant cause of morbidity and mortality in healthcare settings.",a:"B) Healthcare-Associated Infections",r:"HAIs"},
{id:25,s:"IC",t:"sata",q:"Which of the following are common Healthcare-Associated Infections (HAIs)? (Select all that apply)",o:["CAUTI (Catheter-Associated Urinary Tract Infection)","CLABSI (Central Line-Associated Bloodstream Infection)","SSI (Surgical Site Infection)","VAP (Ventilator-Associated Pneumonia)","GERD (Gastroesophageal Reflux Disease)"],c:[0,1,2,3],e:"CAUTI, CLABSI, SSI, and VAP are the four most common HAIs. GERD is a gastrointestinal condition, not an infection. Prevention of HAIs is a major focus of evidence-based nursing practice and quality improvement initiatives.",a:"A, B, C, D",r:"HAIs"},
{id:26,s:"IC",t:"mc",q:"What is the primary purpose of oral care every 2 hours for an intubated patient?",o:["To keep the patient comfortable","To prevent ventilator-associated pneumonia (VAP)","To assess the patient's gag reflex","To provide nutrition through the oral mucosa"],c:[1],e:"Oral care every 2 hours for intubated patients is a key evidence-based intervention to prevent VAP. The endotracheal tube bypasses normal defense mechanisms, and bacteria in the oral cavity can migrate to the lungs. Regular oral care reduces bacterial colonization.",a:"B) To prevent ventilator-associated pneumonia (VAP)",r:"Hygiene & HAI Prevention"},
{id:27,s:"IC",t:"mc",q:"When performing perineal care, the nurse should wipe:",o:["Back to front","Side to side","Front to back","In a circular motion"],c:[2],e:"Perineal care should always be performed from front to back (from the urethral meatus toward the anus). This prevents introducing rectal bacteria into the urinary tract, which is especially important for preventing urinary tract infections in female patients.",a:"C) Front to back",r:"Hygiene"},
{id:28,s:"IC",t:"mc",q:"Contact Precautions require which PPE when entering a patient's room?",o:["N95 respirator and gloves","Surgical mask within 3 feet","Gown and gloves","Gown, gloves, N95, and eye protection"],c:[2],e:"Contact Precautions require a gown and gloves upon entering the room. These are used for patients with infections spread by direct or indirect contact such as C. difficile, MRSA, and VRE. A mask is not required unless there is also a risk of droplet/airborne transmission.",a:"C) Gown and gloves",r:"Contact Precautions"},
{id:29,s:"IC",t:"mc",q:"Droplet Precautions require the nurse to wear a surgical mask when within what distance of the patient?",o:["1 foot","3 feet","6 feet","10 feet"],c:[1],e:"Droplet Precautions require a surgical mask when within 3 feet of the patient. Large respiratory droplets from coughing, sneezing, or talking do not remain airborne and fall to the ground within approximately 3 feet due to gravity.",a:"B) 3 feet",r:"Droplet Precautions"},
{id:30,s:"IC",t:"sata",q:"Which diseases require Airborne Precautions? (Select all that apply)",o:["Measles","Influenza","Tuberculosis","Varicella (chickenpox)","C. difficile"],c:[0,2,3],e:"Remember 'MTV' — Measles, TB, and Varicella require Airborne Precautions (negative pressure room + N95 respirator). Influenza requires Droplet Precautions, and C. difficile requires Contact Precautions with soap-and-water hand hygiene.",a:"A, C, D",r:"Airborne Precautions"},
// --- Triage-Focused IC Questions (31–60) ---
{id:31,s:"IC",t:"mc",q:"A nurse receives four new admissions. Which patient should be placed in a negative pressure room FIRST?",o:["Patient with MRSA wound infection","Patient with suspected tuberculosis","Patient with influenza","Patient with C. difficile diarrhea"],c:[1],e:"Tuberculosis requires Airborne Precautions including a negative pressure (airborne infection isolation) room and N95 respirator. MRSA requires Contact Precautions, influenza requires Droplet Precautions, and C. difficile requires Contact Precautions. The TB patient has priority for the negative pressure room.",a:"B) Patient with suspected tuberculosis",r:"Triage & Airborne Precautions"},
{id:32,s:"IC",t:"mc",q:"The ED has limited isolation rooms. Which patient is the HIGHEST priority for a private room?",o:["Patient with a urinary tract infection","Patient with suspected varicella who has not been isolated","Patient with an infected surgical wound","Patient with pneumonia on antibiotics"],c:[1],e:"Varicella (chickenpox) is an airborne disease that requires a negative pressure room to prevent transmission to susceptible individuals. The other patients do not require airborne isolation. Varicella is highly contagious and poses significant risk to immunocompromised patients.",a:"B) Patient with suspected varicella who has not been isolated",r:"Triage & Isolation"},
{id:33,s:"IC",t:"mc",q:"A nurse is triaging patients in the waiting room. Which patient should be given a surgical mask immediately?",o:["A patient with a laceration on the arm","A patient who is actively coughing and has a fever","A patient with abdominal pain and nausea","A patient with a sprained ankle"],c:[1],e:"Respiratory hygiene/cough etiquette is a Standard Precaution. A patient who is actively coughing with a fever may have a respiratory infection and should be given a surgical mask immediately to contain respiratory droplets and protect other patients.",a:"B) A patient who is actively coughing and has a fever",r:"Triage & Respiratory Hygiene"},
{id:34,s:"IC",t:"mc",q:"Four patients are on the same unit. Which patient should the nurse assess FIRST to prevent HAI transmission?",o:["Patient with a peripheral IV site that is red and tender","Patient scheduled for discharge in 2 hours","Patient requesting pain medication","Patient watching television with family"],c:[0],e:"A red and tender IV site suggests a potential local infection or early CLABSI. This patient should be assessed first because the IV site may need to be discontinued and cultured. Early intervention prevents bloodstream infection and further complications.",a:"A) Patient with a peripheral IV site that is red and tender",r:"Triage & HAI Prevention"},
{id:35,s:"IC",t:"mc",q:"A nurse must decide which patient to see first. Which finding is the MOST urgent infection control concern?",o:["Temperature 37.2°C (99°F)","New-onset confusion in a patient with an indwelling urinary catheter","Patient requesting a bed bath","Patient with a healing surgical incision with no drainage"],c:[1],e:"New-onset confusion in a catheterized patient may indicate a CAUTI progressing to sepsis. This is the most urgent finding because it suggests a systemic response to infection. Temperature 37.2°C is low-grade and the other options are not urgent concerns.",a:"B) New-onset confusion in a patient with an indwelling urinary catheter",r:"Triage & CAUTI"},
{id:36,s:"IC",t:"mc",q:"During a disease outbreak on a medical unit, the charge nurse should triage which action FIRST?",o:["Notify the families of all patients","Implement appropriate isolation precautions for affected patients","Schedule a staff meeting to discuss the outbreak","Review the lunch menu for contamination"],c:[1],e:"The first priority during an outbreak is to implement isolation precautions to contain the spread. This is the most immediate action to protect other patients and staff. Notification and investigation follow after containment measures are in place.",a:"B) Implement appropriate isolation precautions for affected patients",r:"Triage & Outbreak Management"},
{id:37,s:"IC",t:"mc",q:"A nurse is caring for multiple patients. Which patient is at GREATEST risk for developing a healthcare-associated infection?",o:["A 25-year-old patient admitted for observation after a minor fall","A 78-year-old patient with diabetes, a central line, and an indwelling catheter","A 40-year-old patient recovering from an appendectomy, post-op day 3","A 30-year-old patient admitted for dehydration receiving oral fluids"],c:[1],e:"The 78-year-old with diabetes, a central line, and indwelling catheter has multiple risk factors for HAIs: advanced age, chronic disease (diabetes impairs immune function), and two invasive devices (central line = CLABSI risk; catheter = CAUTI risk).",a:"B) A 78-year-old patient with diabetes, a central line, and an indwelling catheter",r:"Triage & HAI Risk"},
{id:38,s:"IC",t:"mc",q:"The nurse is assigning rooms for new admissions. A patient with active measles should be placed:",o:["In a semi-private room with another measles patient","In a negative pressure airborne infection isolation room","In any private room with the door closed","In the hallway until a room opens"],c:[1],e:"Measles is transmitted by the airborne route and requires a negative pressure airborne infection isolation room. Remember 'MTV' — Measles, TB, and Varicella all require this level of isolation. A regular private room is insufficient for airborne pathogens.",a:"B) In a negative pressure airborne infection isolation room",r:"Triage & Airborne Precautions"},
{id:39,s:"IC",t:"mc",q:"Which patient in the ED should be triaged to an isolation area FIRST?",o:["A child with otitis media (ear infection)","An adult with a productive cough, night sweats, and weight loss","A teenager with a fractured wrist","An elderly patient with controlled hypertension"],c:[1],e:"Productive cough, night sweats, and weight loss are classic symptoms of tuberculosis. This patient should be immediately placed in airborne isolation to prevent transmission. TB is highly contagious via the airborne route and poses a risk to all individuals in the ED.",a:"B) An adult with a productive cough, night sweats, and weight loss",r:"Triage & TB"},
{id:40,s:"IC",t:"mc",q:"A nurse on a busy unit must prioritize hand hygiene. Which situation poses the GREATEST risk if hand hygiene is skipped?",o:["Before documenting in the electronic health record","Before inserting a urinary catheter","Before opening a supply drawer","Before adjusting the patient's bed height"],c:[1],e:"Inserting a urinary catheter is an invasive aseptic procedure with direct access to the urinary tract. Skipping hand hygiene before this procedure significantly increases the risk of introducing bacteria and causing a CAUTI, which is a common and preventable HAI.",a:"B) Before inserting a urinary catheter",r:"Triage & Hand Hygiene"},
{id:41,s:"IC",t:"mc",q:"Three patients need care. Which should the nurse see LAST to prevent cross-contamination?",o:["Patient with a clean surgical wound needing a dressing change","Patient receiving IV antibiotics for pneumonia","Patient with active MRSA wound infection requiring wound care"],c:[2],e:"The patient with active MRSA should be seen last to prevent cross-contamination to other patients. Caring for the patient with MRSA last reduces the risk of transmitting this multidrug-resistant organism to the other patients, especially the one with a clean surgical wound.",a:"C) Patient with active MRSA wound infection requiring wound care",r:"Triage & Contact Precautions"},
{id:42,s:"IC",t:"mc",q:"A nurse is triaging phone calls. Which caller describes a situation requiring the MOST urgent infection control response?",o:["'My child has had a runny nose for 2 days.'","'My mother in the nursing home has a new fever and her central line site is red and draining pus.'","'I twisted my ankle while jogging.'","'My husband has seasonal allergies.'"],c:[1],e:"A new fever with redness and purulent drainage at a central line site suggests a CLABSI, which can rapidly progress to sepsis. This is a medical emergency requiring immediate assessment, blood cultures, and potential line removal. The other situations are not urgent.",a:"B) 'My mother in the nursing home has a new fever and her central line site is red and draining pus.'",r:"Triage & CLABSI"},
{id:43,s:"IC",t:"mc",q:"Multiple patients on the unit develop diarrhea over 48 hours. The nurse should FIRST:",o:["Administer antidiarrheal medication to all affected patients","Place affected patients on Contact Precautions and notify infection control","Increase fluid intake for all patients on the unit","Document the findings and continue routine care"],c:[1],e:"A cluster of diarrhea cases suggests a possible C. difficile or norovirus outbreak. The first action is to implement Contact Precautions for affected patients and notify infection control to begin investigation and containment. This prevents further spread.",a:"B) Place affected patients on Contact Precautions and notify infection control",r:"Triage & Outbreak"},
{id:44,s:"IC",t:"mc",q:"A nurse must triage four patients with infections. Which patient can safely share a semi-private room?",o:["A patient with active pulmonary tuberculosis","A patient with varicella (chickenpox)","A patient with a urinary tract infection on standard precautions","A patient with measles"],c:[2],e:"A patient with a UTI on Standard Precautions does not require isolation and can share a room. Patients with TB, varicella, and measles all require airborne isolation in negative pressure rooms and cannot share rooms with other patients.",a:"C) A patient with a urinary tract infection on standard precautions",r:"Triage & Room Assignment"},
{id:45,s:"IC",t:"mc",q:"The charge nurse is assigning patients. Which nurse-patient assignment poses the GREATEST infection risk?",o:["A nurse caring for a patient with MRSA and a patient with a clean surgical wound","A nurse caring for two patients both on standard precautions","A nurse caring for a patient with a UTI and a patient with pneumonia, both on antibiotics","A nurse caring for two patients awaiting discharge"],c:[0],e:"Assigning the same nurse to a patient with MRSA and one with a clean surgical wound creates a high risk of cross-contamination. MRSA could be transmitted to the surgical wound patient, potentially causing a serious surgical site infection (SSI).",a:"A) A nurse caring for a patient with MRSA and a patient with a clean surgical wound",r:"Triage & Safe Assignment"},
// --- Prioritizing-Focused IC Questions (46–75) ---
{id:46,s:"IC",t:"mc",q:"A nurse is caring for a patient on Contact Precautions for VRE. Which action should the nurse prioritize?",o:["Wearing an N95 respirator when entering the room","Donning gown and gloves before entering the room","Placing the patient in a negative pressure room","Wearing a surgical mask within 3 feet"],c:[1],e:"VRE requires Contact Precautions, which means donning a gown and gloves before entering the room. An N95 and negative pressure room are for airborne precautions. A surgical mask within 3 feet is for droplet precautions.",a:"B) Donning gown and gloves before entering the room",r:"Prioritizing & Contact Precautions"},
{id:47,s:"IC",t:"mc",q:"A nurse has four tasks to complete. Which should be done FIRST?",o:["Change the bed linens for a patient who is comfortable","Perform hand hygiene before inserting a peripheral IV","Restock the supply cart","Complete charting from the previous shift"],c:[1],e:"Performing hand hygiene before an invasive procedure (IV insertion) is the highest priority because it directly prevents infection. This is one of the WHO's 5 Moments of Hand Hygiene — 'before an aseptic task.' The other tasks are important but not time-critical for patient safety.",a:"B) Perform hand hygiene before inserting a peripheral IV",r:"Prioritizing & Hand Hygiene"},
{id:48,s:"IC",t:"mc",q:"The nurse observes a UAP (unlicensed assistive personnel) about to enter a C. difficile patient's room using hand sanitizer. The nurse should FIRST:",o:["Allow the UAP to enter since hand sanitizer is adequate","Remind the UAP that soap and water must be used for C. difficile patients","Report the UAP to the charge nurse immediately","Document the incident in the patient's chart"],c:[1],e:"The nurse should immediately intervene and educate the UAP that alcohol-based hand sanitizer is NOT effective against C. difficile spores. Soap and water must be used. 'SOAP it up' — the nurse's first priority is correcting the practice to protect the patient.",a:"B) Remind the UAP that soap and water must be used for C. difficile patients",r:"Prioritizing & C. diff"},
{id:49,s:"IC",t:"mc",q:"A nurse is prioritizing care for a postoperative patient. Which intervention is MOST important for preventing SSI?",o:["Keeping the surgical wound covered for the first 24-48 hours with a sterile dressing","Allowing the patient to shower immediately after surgery","Changing the wound dressing every hour","Applying antibiotic ointment without a provider's order"],c:[0],e:"Evidence-based practice recommends keeping the surgical incision covered with a sterile dressing for the first 24-48 hours postoperatively to prevent surgical site infection (SSI). Premature dressing removal exposes the wound before initial healing occurs.",a:"A) Keeping the surgical wound covered for the first 24-48 hours with a sterile dressing",r:"Prioritizing & SSI Prevention"},
{id:50,s:"IC",t:"mc",q:"A nurse is caring for a patient with a Foley catheter. Which action is the HIGHEST priority for preventing CAUTI?",o:["Securing the catheter to the patient's thigh","Assessing the continued need for the catheter daily and advocating for removal","Emptying the drainage bag once per shift","Irrigating the catheter every 4 hours"],c:[1],e:"The single most effective intervention to prevent CAUTI is removing the catheter as soon as it is no longer needed. Daily assessment of catheter necessity and early removal is the gold standard for CAUTI prevention. Unnecessary catheter days are the leading risk factor.",a:"B) Assessing the continued need for the catheter daily and advocating for removal",r:"Prioritizing & CAUTI Prevention"},
{id:51,s:"IC",t:"mc",q:"When prioritizing infection control measures, which is the MOST effective method to prevent HAIs?",o:["Wearing gloves for all patient contact","Proper hand hygiene","Administering prophylactic antibiotics to all patients","Keeping patient room doors closed"],c:[1],e:"Hand hygiene is the single most effective measure to prevent healthcare-associated infections. While gloves and other PPE are important, they do not replace the need for hand hygiene. Proper hand hygiene before and after patient contact is the cornerstone of infection prevention.",a:"B) Proper hand hygiene",r:"Prioritizing & Infection Prevention"},
{id:52,s:"IC",t:"mc",q:"A nurse is preparing to perform a sterile dressing change and the phone rings. What is the priority action?",o:["Answer the phone while maintaining the sterile field","Ask another staff member to answer the phone and continue the procedure","Abandon the sterile field to answer the phone","Place the call on hold, then return to the procedure"],c:[1],e:"Maintaining sterile technique is the priority during a sterile procedure. The nurse should ask another staff member to handle the phone call. Turning away from or abandoning the sterile field would contaminate it, requiring the procedure to be restarted.",a:"B) Ask another staff member to answer the phone and continue the procedure",r:"Prioritizing & Sterile Technique"},
{id:53,s:"IC",t:"mc",q:"A patient on Droplet Precautions for influenza needs to be transported to radiology. The nurse should PRIORITIZE:",o:["Having the patient wear an N95 respirator during transport","Placing a surgical mask on the patient before transport","Canceling the radiology appointment","Having all staff in the hallway wear N95 respirators"],c:[1],e:"When transporting a patient on Droplet Precautions, the patient should wear a surgical mask to contain respiratory droplets. An N95 is not necessary for droplet precautions — it is used for airborne precautions. Transport should not be canceled if medically necessary.",a:"B) Placing a surgical mask on the patient before transport",r:"Prioritizing & Droplet Precautions"},
{id:54,s:"IC",t:"sata",q:"Which actions should the nurse prioritize to prevent CLABSI? (Select all that apply)",o:["Use maximal sterile barrier precautions during insertion","Perform daily assessment of line necessity","Clean the insertion site with chlorhexidine","Change the central line dressing only when visibly soiled","Perform hand hygiene before accessing the line"],c:[0,1,2,4],e:"CLABSI prevention includes: maximal barrier precautions during insertion, daily assessment of line necessity, chlorhexidine site cleaning, hand hygiene before access, and changing dressings per protocol (not just when visibly soiled). Evidence-based bundles significantly reduce CLABSI rates.",a:"A, B, C, E",r:"Prioritizing & CLABSI Prevention"},
{id:55,s:"IC",t:"mc",q:"A nurse must prioritize between two patients. Patient A has a temperature of 38.9°C and a new central line inserted yesterday. Patient B has a temperature of 37.1°C and is post-op day 2 with a clean incision. Who should be assessed first?",o:["Patient A","Patient B","Either patient — both are stable","Neither — delegate to the UAP"],c:[0],e:"Patient A with a fever and a new central line is at risk for CLABSI and should be assessed first. A temperature of 38.9°C with a central line warrants immediate assessment, blood cultures, and potential line evaluation. Patient B has a low-grade temp and clean wound.",a:"A) Patient A",r:"Prioritizing & CLABSI"},
{id:56,s:"IC",t:"mc",q:"The nurse is delegating tasks to a UAP. Which task is appropriate to delegate?",o:["Assessing a patient's surgical wound for signs of infection","Performing sterile wound irrigation","Assisting a patient on Contact Precautions with a bath while wearing appropriate PPE","Deciding which isolation precautions to implement"],c:[2],e:"A UAP can assist with hygiene care (bathing) as long as they wear appropriate PPE (gown and gloves for Contact Precautions). Assessment, sterile procedures, and clinical decision-making about isolation types are within the nurse's scope and cannot be delegated.",a:"C) Assisting a patient on Contact Precautions with a bath while wearing appropriate PPE",r:"Prioritizing & Delegation"},
{id:57,s:"IC",t:"mc",q:"A nurse notices another nurse about to enter a TB patient's room wearing a surgical mask instead of an N95. The PRIORITY action is:",o:["Document the observation and report it later","Immediately stop the nurse and remind them an N95 is required","Allow them to enter since any mask provides some protection","Report the nurse to the state board of nursing"],c:[1],e:"TB requires Airborne Precautions with an N95 respirator, not a surgical mask. A surgical mask does not filter airborne particles small enough to carry TB. The priority is immediate patient and staff safety — the nurse should be stopped and reminded before exposure occurs.",a:"B) Immediately stop the nurse and remind them an N95 is required",r:"Prioritizing & Airborne Precautions"},
{id:58,s:"IC",t:"mc",q:"When prioritizing infection prevention for a mechanically ventilated patient, which nursing intervention bundle is MOST important?",o:["Keeping the head of bed flat to prevent skin breakdown","Elevating the head of bed 30-45 degrees, oral care q2h, daily sedation vacation, DVT prophylaxis","Suctioning every hour regardless of secretions","Administering IV antibiotics prophylactically"],c:[1],e:"The VAP prevention bundle includes: head of bed elevation 30-45 degrees, oral care every 2 hours, daily sedation vacations, DVT prophylaxis, and peptic ulcer prophylaxis. These evidence-based interventions significantly reduce ventilator-associated pneumonia.",a:"B) Elevating the head of bed 30-45 degrees, oral care q2h, daily sedation vacation, DVT prophylaxis",r:"Prioritizing & VAP Prevention"},
{id:59,s:"IC",t:"mc",q:"A nurse is caring for three patients. In what order should the nurse see them to prioritize infection control?",o:["MRSA wound first, then clean wound, then immunocompromised patient","Immunocompromised patient first, then clean wound, then MRSA wound","Clean wound first, then MRSA wound, then immunocompromised patient","It doesn't matter as long as hand hygiene is performed"],c:[1],e:"The immunocompromised patient should be seen first because they are most vulnerable to infection. Then the patient with a clean wound (moderate risk), and lastly the MRSA patient (source of contamination). This order minimizes the risk of cross-contamination to the most vulnerable patients.",a:"B) Immunocompromised patient first, then clean wound, then MRSA wound",r:"Prioritizing & Patient Order"},
{id:60,s:"IC",t:"sata",q:"Which of the following are appropriate indications for an indwelling urinary catheter? (Select all that apply)",o:["Patient convenience for the nursing staff","Accurate urine output measurement in a critically ill patient","Urinary retention that cannot be managed otherwise","Patient undergoing prolonged surgery","Patient who is ambulatory and continent"],c:[1,2,3],e:"Appropriate catheter indications include: accurate I&O in critically ill patients, urinary retention, prolonged surgical procedures, and comfort care for end-of-life. Staff convenience and ambulatory continent patients are NOT appropriate indications and increase CAUTI risk unnecessarily.",a:"B, C, D",r:"Prioritizing & CAUTI Prevention"},
{id:61,s:"IC",t:"mc",q:"A patient asks why their indwelling catheter must be removed. The nurse's BEST response is:",o:["'Your doctor ordered it removed.'","'The longer the catheter is in place, the greater your risk of developing a urinary tract infection.'","'We need the catheter for another patient.'","'All catheters are removed after 24 hours.'"],c:[1],e:"Patient education about HAI risk is essential. The nurse should explain that every day a catheter remains in place increases CAUTI risk. This is honest, educational, and promotes the patient's understanding of their care. The other responses are either dismissive or incorrect.",a:"B) 'The longer the catheter is in place, the greater your risk of developing a urinary tract infection.'",r:"Prioritizing & Patient Education"},
{id:62,s:"IC",t:"mc",q:"A nurse is setting up a sterile field for a wound irrigation. Which action takes PRIORITY?",o:["Opening the sterile package away from the body","Checking the expiration date of the sterile kit","Ensuring the work surface is clean and dry","Gathering all necessary supplies before opening the kit"],c:[1],e:"Checking the expiration date is the first priority before any sterile procedure. Using an expired kit compromises sterility and patient safety. While all other actions are important steps in setting up a sterile field, verifying that supplies are not expired comes first.",a:"B) Checking the expiration date of the sterile kit",r:"Prioritizing & Sterile Technique"},
{id:63,s:"IC",t:"mc",q:"A nurse must prioritize which infection control education for a new graduate nurse. Which concept is MOST fundamental?",o:["Sterile gloving technique","The 5 moments of hand hygiene","How to apply a negative pressure wound vac","Blood transfusion protocols"],c:[1],e:"Hand hygiene is the single most important infection prevention measure and is fundamental to ALL patient care. The 5 moments of hand hygiene should be the first and most emphasized concept for any new nurse, as it applies to every patient encounter.",a:"B) The 5 moments of hand hygiene",r:"Prioritizing & Education"},
{id:64,s:"IC",t:"mc",q:"A nurse is caring for a patient with pertussis (whooping cough). Which precaution type should the nurse PRIORITIZE?",o:["Standard Precautions only","Contact Precautions","Droplet Precautions","Airborne Precautions"],c:[2],e:"Pertussis is spread through respiratory droplets and requires Droplet Precautions. The nurse should wear a surgical mask within 3 feet of the patient. Pertussis is NOT airborne — it does not remain suspended in the air like TB, measles, or varicella.",a:"C) Droplet Precautions",r:"Prioritizing & Droplet Precautions"},
{id:65,s:"IC",t:"mc",q:"A nurse is prioritizing interventions for a patient with a new tracheostomy. Which infection prevention action is MOST important?",o:["Using sterile technique for tracheostomy care","Keeping the room temperature warm","Positioning the patient in low-Fowler's position","Restricting all visitors"],c:[0],e:"A tracheostomy creates a direct portal of entry to the lower respiratory tract. Sterile technique during tracheostomy care is essential to prevent introducing pathogens into the airway. This is the most important infection prevention intervention for this patient.",a:"A) Using sterile technique for tracheostomy care",r:"Prioritizing & Sterile Technique"},
{id:66,s:"IC",t:"tf",q:"True or False: Transmission-Based Precautions are used INSTEAD OF Standard Precautions.",o:["True","False"],c:[1],e:"False. Transmission-Based Precautions (Contact, Droplet, Airborne) are used IN ADDITION TO Standard Precautions, never instead of. Standard Precautions are always the baseline for all patients, and additional precautions are layered on top when specific infections are suspected or confirmed.",a:"B) False",r:"Precaution Types"},
{id:67,s:"IC",t:"tf",q:"True or False: A nurse should perform hand hygiene after touching a patient's bed rails, even if they did not touch the patient.",o:["True","False"],c:[0],e:"True. The 5th moment of hand hygiene is 'after touching patient surroundings.' Bed rails, bedside tables, IV poles, and other items in the patient's environment can harbor pathogens. Hand hygiene is required after touching these surfaces, even without direct patient contact.",a:"A) True",r:"Hand Hygiene"},
{id:68,s:"IC",t:"mc",q:"A nurse must prioritize teaching for a patient being discharged with a wound. Which topic is MOST important?",o:["When to resume normal activities","Signs and symptoms of wound infection to report","How to style clothing around the wound","When to schedule a follow-up haircut"],c:[1],e:"Teaching the patient to recognize signs of wound infection (redness, swelling, warmth, drainage, fever, increased pain) is the highest priority for safe discharge. Early recognition of SSI symptoms allows for prompt treatment and prevents complications.",a:"B) Signs and symptoms of wound infection to report",r:"Prioritizing & Discharge Teaching"},
{id:69,s:"IC",t:"mc",q:"Which patient should the nurse prioritize for reassessment related to infection risk?",o:["A patient with a peripheral IV inserted 96 hours ago","A patient with a peripheral IV inserted 24 hours ago","A patient with no invasive devices","A patient whose IV was removed this morning"],c:[0],e:"Peripheral IV catheters should generally be assessed and considered for replacement every 72-96 hours to prevent phlebitis and catheter-related bloodstream infection. A peripheral IV at 96 hours is overdue for reassessment and poses the highest infection risk among these options.",a:"A) A patient with a peripheral IV inserted 96 hours ago",r:"Prioritizing & IV Infection Prevention"},
{id:70,s:"IC",t:"mc",q:"A nurse is prioritizing education for UAPs on the unit. Which topic should be addressed FIRST?",o:["How to ambulate a patient with a walker","Proper hand hygiene technique and the 5 moments","How to serve meal trays","How to make an occupied bed"],c:[1],e:"Hand hygiene is the most fundamental infection control measure and should be the first topic taught to all healthcare personnel, including UAPs. Proper hand hygiene technique directly impacts patient safety and HAI prevention across all care activities.",a:"B) Proper hand hygiene technique and the 5 moments",r:"Prioritizing & Staff Education"},
{id:71,s:"IC",t:"mc",q:"A nurse must decide which patient to bathe first. Which patient should have priority?",o:["A patient who is ambulatory and can shower independently","An intubated patient in the ICU who has not had a bath in 12 hours","A patient reading in bed who requests a bath later","A patient who just returned from physical therapy"],c:[1],e:"The intubated ICU patient should be prioritized because immobile, intubated patients are at high risk for skin breakdown and infection. Regular bathing and skin assessment are essential for this vulnerable population. They depend entirely on nursing staff for hygiene.",a:"B) An intubated patient in the ICU who has not had a bath in 12 hours",r:"Prioritizing & Hygiene"},
{id:72,s:"IC",t:"mc",q:"A nurse is prioritizing which personal protective equipment to don first. According to the donning sequence, what goes on first after hand hygiene?",o:["Gloves","Eye protection","Gown","Mask"],c:[2],e:"After hand hygiene, the gown is applied first in the donning sequence. The order is: Hand hygiene → Gown → Mask/N95 → Eye protection → Gloves. The gown goes on first because other PPE is applied over it.",a:"C) Gown",r:"Prioritizing & PPE Sequence"},
{id:73,s:"IC",t:"mc",q:"A nurse discovers that a sterile package has a small tear in the wrapper. The PRIORITY action is:",o:["Use the package if the tear is small","Consider the package contaminated and obtain a new one","Tape over the tear and use the package","Ask a colleague if the tear matters"],c:[1],e:"Any breach in a sterile package's integrity, no matter how small, means the contents are no longer considered sterile. The package must be discarded and a new sterile package obtained. Sterility cannot be verified once the barrier is compromised.",a:"B) Consider the package contaminated and obtain a new one",r:"Prioritizing & Sterile Technique"},
{id:74,s:"IC",t:"mc",q:"A patient with meningococcal meningitis is being admitted. The nurse should FIRST:",o:["Prepare a negative pressure room","Initiate Droplet Precautions and wear a surgical mask","Apply Contact Precautions only","Place the patient in a regular room with no special precautions"],c:[1],e:"Meningococcal meningitis requires Droplet Precautions. The nurse should wear a surgical mask when within 3 feet of the patient. Meningococcal disease is transmitted via respiratory droplets, not the airborne route, so a negative pressure room is not required.",a:"B) Initiate Droplet Precautions and wear a surgical mask",r:"Prioritizing & Droplet Precautions"},
{id:75,s:"IC",t:"mc",q:"When prioritizing patient safety, the nurse knows that the MOST common mode of transmission of HAIs is:",o:["Airborne transmission","Droplet transmission","Direct and indirect contact","Vector-borne transmission"],c:[2],e:"Direct and indirect contact is the most common mode of HAI transmission in healthcare settings. This includes hand-to-patient contact and contact with contaminated surfaces or equipment. This is why hand hygiene is emphasized as the primary prevention measure.",a:"C) Direct and indirect contact",r:"Prioritizing & Transmission"},
// --- Complex Scenario IC Questions (76–110) ---
{id:76,s:"IC",t:"mc",q:"A nurse is caring for a patient with active TB in a negative pressure room. The nurse enters the room wearing an N95 respirator, removes it in the room to take a drink of water, then puts it back on. What is the BEST analysis of this situation?",o:["This is acceptable practice since the nurse put the N95 back on","The nurse broke airborne precautions by removing the N95 in the patient's room","The nurse should have used a surgical mask instead","The N95 only needs to be worn during direct patient care, not while in the room"],c:[1],e:"Removing an N95 respirator at any time while in a negative pressure room with a TB patient breaks airborne precautions and exposes the nurse to airborne TB particles. The nurse should never eat, drink, or remove respiratory protection in an isolation room.",a:"B) The nurse broke airborne precautions by removing the N95 in the patient's room",r:"Complex & Airborne Precautions"},
{id:77,s:"IC",t:"mc",q:"A patient with MRSA in a wound is being discharged home. The patient's family asks how to prevent spreading MRSA. The nurse's BEST response includes:",o:["'MRSA cannot be spread at home, only in hospitals.'","'Wash your hands frequently with soap and water, do not share personal items like towels, and keep the wound covered with a clean bandage.'","'Everyone in the household should take prophylactic antibiotics.'","'The patient should be isolated in a separate room indefinitely.'"],c:[1],e:"MRSA can be spread in community settings. Key prevention strategies include frequent hand washing, not sharing personal items (towels, razors), keeping wounds covered, and cleaning frequently touched surfaces. Antibiotics are not given prophylactically to household contacts.",a:"B) 'Wash your hands frequently with soap and water, do not share personal items like towels, and keep the wound covered with a clean bandage.'",r:"Complex & MRSA Education"},
{id:78,s:"IC",t:"sata",q:"A nurse is caring for a patient with suspected C. difficile. Which interventions should the nurse implement? (Select all that apply)",o:["Place the patient on Contact Precautions","Use alcohol-based hand rub before and after care","Use soap and water for hand hygiene","Dedicate patient care equipment (stethoscope, thermometer)","Request a private room for the patient"],c:[0,2,3,4],e:"C. difficile requires Contact Precautions with soap and water for hand hygiene (alcohol does NOT kill C. diff spores — remember 'SOAP it up'). Dedicated equipment prevents indirect contact transmission. A private room reduces environmental contamination risk.",a:"A, C, D, E",r:"Complex & C. diff Management"},
{id:79,s:"IC",t:"mc",q:"A nurse is setting up a sterile field for a central line dressing change. A non-sterile supply falls onto the sterile field. The CORRECT action is to:",o:["Remove the non-sterile item with sterile forceps and continue","Discard the entire sterile field and start over","Remove the item and cover the contaminated area with a sterile towel","Continue the procedure since the item can be moved aside"],c:[1],e:"Any non-sterile object that contacts the sterile field contaminates the entire field. The nurse must discard everything and set up a completely new sterile field. There is no way to re-sterilize a contaminated field. Patient safety requires a fresh start.",a:"B) Discard the entire sterile field and start over",r:"Complex & Sterile Technique"},
{id:80,s:"IC",t:"mc",q:"A patient on airborne precautions for varicella needs an emergent CT scan. The CORRECT transport procedure includes:",o:["Canceling the CT scan to maintain isolation","Having the patient wear an N95 respirator and notifying the receiving department in advance","Having the patient wear a surgical mask, covering exposed lesions, and notifying receiving department","Transporting the patient without any mask since the trip is short"],c:[2],e:"For varicella transport, the patient should wear a surgical mask (N95s are for healthcare workers), exposed lesions should be covered, and the receiving department should be notified in advance to prepare. The CT scan should not be canceled if it is emergent.",a:"C) Having the patient wear a surgical mask, covering exposed lesions, and notifying receiving department",r:"Complex & Transport Precautions"},
{id:81,s:"IC",t:"mc",q:"A nurse receives a needlestick injury while drawing blood from a patient with unknown HIV status. The FIRST action should be:",o:["Complete an incident report immediately","Wash the site thoroughly with soap and water","Apply a bandage and continue working","Call the patient's family to ask about HIV status"],c:[1],e:"After a needlestick injury, the immediate first action is to wash the puncture site thoroughly with soap and water (do not squeeze the wound). Then report the exposure to the supervisor, complete an incident report, seek evaluation for post-exposure prophylaxis (PEP), and have the source patient tested.",a:"B) Wash the site thoroughly with soap and water",r:"Complex & Exposure Management"},
{id:82,s:"IC",t:"mc",q:"A nurse caring for a patient with VRE removes gloves and immediately enters the next patient's room without hand hygiene. Which statement BEST describes the risk?",o:["No risk since gloves prevented contamination","The nurse may transmit VRE to the next patient via contaminated hands","The risk is minimal since VRE is not easily spread","Hand hygiene is only needed before patient contact, not after"],c:[1],e:"Gloves do not provide 100% protection — hands can become contaminated during glove removal or through micro-perforations. Skipping hand hygiene after removing gloves and before entering another patient's room creates a serious risk of cross-contamination with VRE.",a:"B) The nurse may transmit VRE to the next patient via contaminated hands",r:"Complex & Cross-Contamination"},
{id:83,s:"IC",t:"mc",q:"A patient with neutropenia (low white blood cell count) is admitted. The nurse should PRIORITIZE which protective measure?",o:["Placing the patient on Contact Precautions","Implementing Protective (Reverse) Isolation — private room, strict hand hygiene, no fresh flowers/plants","Allowing unlimited visitors to boost the patient's morale","Placing the patient in a negative pressure room"],c:[1],e:"Neutropenic patients are severely immunocompromised and require protective (reverse) isolation to protect THEM from environmental pathogens. This includes a private room, meticulous hand hygiene by all who enter, no fresh flowers or plants (harbor mold/bacteria), and limiting visitors who are ill.",a:"B) Implementing Protective (Reverse) Isolation — private room, strict hand hygiene, no fresh flowers/plants",r:"Complex & Protective Isolation"},
{id:84,s:"IC",t:"mc",q:"A surgical nurse notices a break in sterile technique by another team member during an operation. The CORRECT action is:",o:["Ignore it to avoid conflict during surgery","Immediately and assertively call attention to the break in sterile technique","Document it after surgery and discuss it later","Wait until the surgery is complete to address it"],c:[1],e:"Patient safety always takes priority. A break in sterile technique during surgery must be addressed immediately to prevent surgical site infection. The nurse has a professional and ethical obligation to speak up. Delaying correction increases the risk of patient harm.",a:"B) Immediately and assertively call attention to the break in sterile technique",r:"Complex & Sterile Technique"},
{id:85,s:"IC",t:"sata",q:"A nurse is implementing a CAUTI prevention bundle. Which interventions should be included? (Select all that apply)",o:["Daily assessment of catheter necessity","Maintaining a closed drainage system","Securing the catheter to prevent pulling","Raising the collection bag above the level of the bladder","Performing perineal hygiene"],c:[0,1,2,4],e:"CAUTI prevention bundles include: daily catheter necessity assessment, closed drainage system, catheter securement, keeping the drainage bag BELOW the bladder (never above — gravity drainage), and regular perineal hygiene. Raising the bag above the bladder promotes urine backflow and infection.",a:"A, B, C, E",r:"Complex & CAUTI Bundle"},
{id:86,s:"IC",t:"mc",q:"A nurse is floating to a new unit and is unsure what precautions a patient requires. The BEST action is:",o:["Use Standard Precautions only and proceed with care","Check the patient's chart and the isolation signage on the door before entering","Ask the patient what precautions are needed","Call the infection preventionist at home"],c:[1],e:"The nurse should always verify isolation requirements by checking the patient's chart/orders and the isolation signage posted on the door before entering the room. This ensures the correct PPE is used and proper precautions are followed, protecting both the patient and the nurse.",a:"B) Check the patient's chart and the isolation signage on the door before entering",r:"Complex & Safe Practice"},
{id:87,s:"IC",t:"mc",q:"A nurse notices that the urinary catheter drainage bag is touching the floor. The CORRECT action is:",o:["This is acceptable as long as the bag is below the bladder","Reposition the bag so it hangs below the bladder but above the floor","Disconnect the bag and replace it with a new one","Clamp the catheter until the bag can be repositioned"],c:[1],e:"The drainage bag should always hang below the level of the bladder (to maintain gravity drainage) but should NEVER touch the floor. The floor is highly contaminated, and contact with the bag increases CAUTI risk. Reposition the bag to hang freely above the floor.",a:"B) Reposition the bag so it hangs below the bladder but above the floor",r:"Complex & CAUTI Prevention"},
{id:88,s:"IC",t:"mc",q:"A patient with a suspected airborne infection refuses to stay in their negative pressure room and walks to the cafeteria. The nurse should FIRST:",o:["Call security immediately","Calmly approach the patient, provide a mask, explain the importance of isolation, and escort them back","Document the patient's non-compliance and move on","Allow the patient to remain in the cafeteria since they have rights"],c:[1],e:"While patients have rights, they also have a responsibility not to expose others. The nurse should calmly approach, provide a mask to reduce transmission risk, educate the patient about why isolation is necessary, and escort them back. Therapeutic communication and education come before calling security.",a:"B) Calmly approach the patient, provide a mask, explain the importance of isolation, and escort them back",r:"Complex & Patient Compliance"},
{id:89,s:"IC",t:"order",q:"Place the following steps for establishing a sterile field in the correct order.",o:["Verify the sterile package expiration date and integrity","Perform hand hygiene","Open the sterile package using proper technique","Add sterile items by dropping them onto the field","Apply sterile gloves"],c:[1,0,2,3,4],e:"The correct order is: hand hygiene first, then verify package integrity/expiration, open the sterile package, add sterile items by dropping them onto the field without reaching over it, then apply sterile gloves. Verification before opening prevents waste of contaminated supplies.",a:"Hand hygiene → Verify package → Open package → Add sterile items → Apply sterile gloves",r:"Complex & Sterile Field Setup"},
{id:90,s:"IC",t:"mc",q:"A patient asks the nurse, 'Why do you wash your hands so much? Don't the gloves protect you?' The BEST response is:",o:["'It's hospital policy, and I have to follow it.'","'Gloves can have tiny holes, and hand hygiene before and after wearing gloves prevents the spread of germs to protect both of us.'","'You're right, gloves do protect me, but I wash my hands out of habit.'","'I only do it because my supervisor is watching.'"],c:[1],e:"The nurse should provide honest, educational information. Gloves can have micro-perforations and hands can become contaminated during removal. Hand hygiene before and after glove use is essential for both patient and nurse protection. This response promotes patient understanding.",a:"B) 'Gloves can have tiny holes, and hand hygiene before and after wearing gloves prevents the spread of germs to protect both of us.'",r:"Complex & Patient Education"},
{id:91,s:"IC",t:"mc",q:"A nurse observes that the UAP is reusing a blood pressure cuff between patients on Contact Precautions without disinfecting it. The nurse should:",o:["Ignore it since the UAP is busy","Immediately intervene and educate the UAP about the need to disinfect shared equipment or use dedicated equipment","Report the UAP to human resources","Tell the patient to refuse to have their blood pressure taken"],c:[1],e:"Shared patient care equipment can transmit infections through indirect contact. Patients on Contact Precautions should have dedicated equipment or equipment must be disinfected between patients. The nurse has a duty to intervene immediately and educate to prevent transmission.",a:"B) Immediately intervene and educate the UAP about the need to disinfect shared equipment or use dedicated equipment",r:"Complex & Contact Precautions"},
{id:92,s:"IC",t:"mc",q:"A post-surgical patient develops a fever, redness, and purulent drainage at the incision site on post-op day 4. The nurse suspects:",o:["Normal post-operative healing","Surgical site infection (SSI)","An allergic reaction to the sutures","Dehydration"],c:[1],e:"Fever, redness, and purulent drainage at a surgical incision site are classic signs of SSI, especially appearing on post-op day 4 (within the typical SSI window). Normal healing does not include purulent drainage. The nurse should notify the provider and obtain wound cultures as ordered.",a:"B) Surgical site infection (SSI)",r:"Complex & SSI Recognition"},
{id:93,s:"IC",t:"mc",q:"A patient on Contact Precautions for C. difficile needs to use the bathroom. The nurse should:",o:["Have the patient use a bedside commode dedicated to the patient","Allow the patient to use the shared bathroom in the hallway","Tell the patient to wait until the isolation is lifted","Use a bedpan only — the patient should not leave the bed"],c:[0],e:"Patients with C. difficile should ideally have a private bathroom or a dedicated bedside commode. C. difficile spores can survive on environmental surfaces for months, and shared bathrooms increase the risk of transmission to other patients.",a:"A) Have the patient use a bedside commode dedicated to the patient",r:"Complex & C. diff Environment"},
{id:94,s:"IC",t:"mc",q:"A nurse is preparing to insert a Foley catheter. After setting up the sterile field, the nurse realizes they forgot to get lubricant. The CORRECT action is:",o:["Reach across the sterile field to get the lubricant from the supply cart","Ask another staff member to open and drop the lubricant onto the sterile field","Leave the sterile field unattended to get the lubricant","Use the catheter without lubricant to avoid contaminating the field"],c:[1],e:"The nurse should never leave or reach across a sterile field. The best action is to ask another staff member to open the lubricant package and drop it onto the sterile field. This maintains sterility while obtaining the needed supply. Always gather all supplies before starting.",a:"B) Ask another staff member to open and drop the lubricant onto the sterile field",r:"Complex & Sterile Technique"},
{id:95,s:"IC",t:"fib",q:"The mnemonic for remembering which diseases require Airborne Precautions is ____.",o:[],c:["MTV"],e:"MTV stands for Measles, Tuberculosis, and Varicella. These three diseases require Airborne Precautions because their pathogens are small enough to remain suspended in the air and travel long distances. They require a negative pressure room and N95 respirator.",a:"MTV",r:"Airborne Precautions Mnemonic"},
{id:96,s:"IC",t:"fib",q:"The mnemonic for remembering the chain of infection is 'I Rest My ____ ____ ____.'",o:[],c:["Peanut Butter Sandwich"],e:"'I Rest My Peanut Butter Sandwich' helps remember: Infectious agent, Reservoir, Mode of transmission, Portal of exit (Peanut), Portal of entry (Butter), Susceptible host (Sandwich). Breaking any link prevents infection transmission.",a:"Peanut Butter Sandwich",r:"Chain of Infection Mnemonic"},
{id:97,s:"IC",t:"mc",q:"A nurse is wearing an N95 respirator to care for a TB patient. The nurse sneezes inside the respirator. The BEST action is:",o:["Remove the N95 immediately and replace it","Leave the room to remove and replace the N95, then re-enter after performing hand hygiene","Continue wearing the same N95 without any action","Remove the N95, wipe the inside, and put it back on"],c:[1],e:"After sneezing inside an N95, the inside is now moist and potentially contaminated. The nurse should leave the room (the respirator is still protective for the brief exit), remove and discard the N95, perform hand hygiene, and put on a new N95 before re-entering.",a:"B) Leave the room to remove and replace the N95, then re-enter after performing hand hygiene",r:"Complex & N95 Use"},
{id:98,s:"IC",t:"tf",q:"True or False: Items below waist level are considered contaminated in sterile technique.",o:["True","False"],c:[0],e:"True. In sterile technique, only items at or above waist level are considered sterile. Anything that falls below the waist is considered contaminated because it is out of the practitioner's direct line of sight and more likely to contact non-sterile surfaces.",a:"A) True",r:"Sterile Technique"},
{id:99,s:"IC",t:"mc",q:"A visitor arrives to see a patient on Droplet Precautions. The nurse should instruct the visitor to:",o:["Wear an N95 respirator","Wear a surgical mask when within 3 feet of the patient","Wear a gown and gloves only","No special precautions are needed for visitors"],c:[1],e:"Visitors of patients on Droplet Precautions should wear a surgical mask when within 3 feet of the patient, just as healthcare workers do. An N95 is only required for airborne precautions. The visitor should also perform hand hygiene before and after the visit.",a:"B) Wear a surgical mask when within 3 feet of the patient",r:"Complex & Visitor Education"},
{id:100,s:"IC",t:"mc",q:"A nurse is caring for a post-operative patient and notices that the Jackson-Pratt (JP) drain output has changed from serosanguineous to thick, green, foul-smelling drainage. This finding suggests:",o:["Normal healing progression","Wound infection requiring immediate provider notification","The drain needs to be irrigated","The patient is dehydrated"],c:[1],e:"Thick, green, foul-smelling drainage from a surgical drain is a sign of infection. Normal postoperative drainage progresses from sanguineous to serosanguineous to serous. The nurse should immediately notify the provider for wound culture and potential antibiotic therapy.",a:"B) Wound infection requiring immediate provider notification",r:"Complex & SSI Assessment"},
{id:101,s:"IC",t:"sata",q:"Which of the following are principles of sterile technique? (Select all that apply)",o:["A 1-inch border around the sterile field is contaminated","Only sterile items may be placed on the sterile field","A sterile field may be left unattended briefly if covered","Items below waist level are considered contaminated","Moisture contaminates a sterile field"],c:[0,1,3,4],e:"Sterile field principles include: 1-inch border is contaminated, only sterile items on the field, items below waist are contaminated, moisture causes strike-through contamination. A sterile field should NEVER be left unattended, even if covered — it is considered contaminated.",a:"A, B, D, E",r:"Complex & Sterile Technique"},
{id:102,s:"IC",t:"mc",q:"A patient is admitted with shingles (herpes zoster) with disseminated lesions. Which isolation precautions are required?",o:["Standard Precautions only","Contact Precautions only","Airborne AND Contact Precautions","Droplet Precautions only"],c:[2],e:"Disseminated herpes zoster (shingles) requires BOTH Airborne and Contact Precautions because the varicella-zoster virus can become airborne from disseminated lesions AND is spread by direct contact with vesicular fluid. Localized shingles requires Contact Precautions only.",a:"C) Airborne AND Contact Precautions",r:"Complex & Combined Precautions"},
{id:103,s:"IC",t:"mc",q:"A nurse is performing wound care and realizes they touched the outside of the sterile glove with their bare hand during gloving. The CORRECT action is:",o:["Continue — touching the outside of the sterile glove is acceptable with clean hands","Remove both gloves, perform hand hygiene, and re-glove with new sterile gloves","Wipe the glove with alcohol and continue","Only replace the contaminated glove"],c:[1],e:"The outside of sterile gloves must only be touched by another sterile surface. Bare hands touching the outer sterile surface contaminates the glove. Both gloves should be removed, hand hygiene performed, and new sterile gloves applied. Only sterile-to-sterile contact is acceptable.",a:"B) Remove both gloves, perform hand hygiene, and re-glove with new sterile gloves",r:"Complex & Sterile Gloving"},
{id:104,s:"IC",t:"tf",q:"True or False: A nurse should always perform hand hygiene after doffing all PPE.",o:["True","False"],c:[0],e:"True. Hand hygiene is the final step in the PPE doffing sequence: Gloves → Eye protection → Gown → Mask → Hand hygiene. Hands may become contaminated during the removal process, so thorough hand hygiene afterward is essential to prevent self-contamination and cross-contamination.",a:"A) True",r:"PPE Doffing"},
{id:105,s:"IC",t:"mc",q:"A nurse is caring for a patient with both MRSA pneumonia and active tuberculosis. Which precautions should be implemented?",o:["Contact Precautions only","Airborne Precautions only","Contact and Airborne Precautions combined","Standard Precautions only"],c:[2],e:"This patient requires Contact Precautions for MRSA (gown and gloves) AND Airborne Precautions for TB (negative pressure room and N95 respirator). When a patient has multiple infections, precautions are combined to address all transmission routes.",a:"C) Contact and Airborne Precautions combined",r:"Complex & Combined Precautions"},
{id:106,s:"IC",t:"mc",q:"A nurse enters a patient's room and finds the patient's roommate coughing heavily. The patient has an open abdominal wound. The nurse's PRIORITY concern is:",o:["The coughing roommate may need cough suppressant medication","Airborne or droplet pathogens from the coughing roommate could contaminate the patient's wound","The noise may disturb the patient's rest","The roommate's coughing is a normal occurrence"],c:[1],e:"An actively coughing roommate poses an infection risk to a patient with an open wound through droplet transmission. The nurse should assess the roommate's symptoms, implement respiratory hygiene measures, and consider room separation to protect the vulnerable patient.",a:"B) Airborne or droplet pathogens from the coughing roommate could contaminate the patient's wound",r:"Complex & Cross-Contamination Risk"},
{id:107,s:"IC",t:"order",q:"Place the following steps in the correct order for performing hand hygiene with soap and water.",o:["Wet hands with water","Apply soap","Lather and scrub all surfaces for at least 20 seconds","Rinse hands thoroughly under running water","Dry with a clean paper towel and use the towel to turn off the faucet"],c:[0,1,2,3,4],e:"Proper handwashing technique: wet hands first, apply soap, lather all surfaces (between fingers, under nails, backs of hands) for at least 20 seconds, rinse thoroughly, and dry with a paper towel. Using the towel to turn off the faucet prevents recontamination.",a:"Wet → Soap → Lather 20 sec → Rinse → Dry with towel and use towel to turn off faucet",r:"Complex & Hand Hygiene Technique"},
{id:108,s:"IC",t:"mc",q:"A nurse is admitting a patient from a long-term care facility who has a history of MRSA colonization but no active infection. The nurse should:",o:["Place the patient on Airborne Precautions","Implement Standard Precautions and follow facility policy for MRSA-colonized patients","Place the patient in reverse isolation","Refuse to admit the patient until MRSA is cleared"],c:[1],e:"MRSA-colonized patients (carrying the organism but not actively infected) should be managed per facility policy, which may include Contact Precautions or enhanced Standard Precautions. Airborne and reverse isolation are not appropriate. Patients cannot be refused admission for colonization status.",a:"B) Implement Standard Precautions and follow facility policy for MRSA-colonized patients",r:"Complex & MRSA Colonization"},
{id:109,s:"IC",t:"tf",q:"True or False: Gloves should be changed between tasks on the same patient, such as moving from a contaminated body site to a clean body site.",o:["True","False"],c:[0],e:"True. Gloves should be changed between dirty and clean tasks on the same patient to prevent transferring microorganisms from a contaminated area to a clean area. For example, change gloves after cleaning a wound and before handling a clean IV site. Hand hygiene should be performed between glove changes.",a:"A) True",r:"Complex & Glove Use"},
{id:110,s:"IC",t:"mc",q:"A patient's family member with a known active upper respiratory infection wants to visit a neutropenic patient. The nurse should:",o:["Allow the visit since family support is important for healing","Restrict the visit and educate the family member about the risk to the immunocompromised patient","Provide the family member with a gown and allow entry","Allow a brief 5-minute visit only"],c:[1],e:"Visitors with active infections should be restricted from visiting neutropenic (immunocompromised) patients. The risk of transmitting infection to the vulnerable patient outweighs the benefits of the visit. The nurse should educate the family and suggest alternative contact methods like phone or video call.",a:"B) Restrict the visit and educate the family member about the risk to the immunocompromised patient",r:"Complex & Protective Isolation"},
// --- Additional IC General Questions (111–130) ---
{id:111,s:"IC",t:"mc",q:"Which link in the chain of infection does hand hygiene PRIMARILY break?",o:["Infectious agent","Reservoir","Mode of transmission","Susceptible host"],c:[2],e:"Hand hygiene primarily breaks the mode of transmission link in the chain of infection. By cleaning the hands, the nurse interrupts the pathway by which pathogens are transferred from one person or surface to another, preventing the spread of infection.",a:"C) Mode of transmission",r:"Chain of Infection"},
{id:112,s:"IC",t:"mc",q:"Vaccination of healthcare workers primarily breaks which link in the chain of infection?",o:["Infectious agent","Portal of exit","Mode of transmission","Susceptible host"],c:[3],e:"Vaccination makes the healthcare worker immune to the pathogen, thereby eliminating them as a susceptible host. Even if exposed, a vaccinated individual is less likely to develop infection. This breaks the final link in the chain of infection.",a:"D) Susceptible host",r:"Chain of Infection"},
{id:113,s:"IC",t:"mc",q:"Which statement about Standard Precautions is CORRECT?",o:["They are only needed for patients with known infections","They include hand hygiene, PPE use, respiratory hygiene, and safe injection practices for ALL patients","They replace the need for Transmission-Based Precautions","They only apply to blood and blood products"],c:[1],e:"Standard Precautions are the minimum infection prevention practices applied to ALL patients in ALL healthcare settings, regardless of suspected or confirmed infection. They include hand hygiene, PPE, respiratory hygiene, safe injection practices, and safe handling of contaminated equipment.",a:"B) They include hand hygiene, PPE use, respiratory hygiene, and safe injection practices for ALL patients",r:"Standard Precautions"},
{id:114,s:"IC",t:"sata",q:"Which of the following require Contact Precautions? (Select all that apply)",o:["C. difficile","MRSA","Tuberculosis","VRE","Influenza"],c:[0,1,3],e:"C. difficile, MRSA, and VRE all require Contact Precautions (gown + gloves). Tuberculosis requires Airborne Precautions (N95 + negative pressure room). Influenza requires Droplet Precautions (surgical mask within 3 feet).",a:"A, B, D",r:"Contact Precautions"},
{id:115,s:"IC",t:"sata",q:"Which diseases require Droplet Precautions? (Select all that apply)",o:["Influenza","Pertussis (whooping cough)","Meningococcal meningitis","Measles","Tuberculosis"],c:[0,1,2],e:"Influenza, pertussis, and meningococcal meningitis are transmitted by large respiratory droplets and require Droplet Precautions (surgical mask within 3 feet). Measles and tuberculosis are transmitted by airborne particles and require Airborne Precautions.",a:"A, B, C",r:"Droplet Precautions"},
{id:116,s:"IC",t:"mc",q:"The nurse is caring for a patient with a central venous catheter. Which intervention is MOST important for preventing CLABSI?",o:["Changing the dressing daily regardless of its condition","Performing hand hygiene and scrubbing the hub for 15 seconds before each access","Drawing blood cultures from the line every shift","Flushing the line with heparin every hour"],c:[1],e:"Hand hygiene before line access and scrubbing the catheter hub with antiseptic for at least 15 seconds ('scrub the hub') before each access is the most important CLABSI prevention intervention. This removes microorganisms that could enter the bloodstream during access.",a:"B) Performing hand hygiene and scrubbing the hub for 15 seconds before each access",r:"CLABSI Prevention"},
{id:117,s:"IC",t:"tf",q:"True or False: Medical asepsis (clean technique) eliminates ALL microorganisms.",o:["True","False"],c:[1],e:"False. Medical asepsis (clean technique) reduces the number and transfer of pathogens but does NOT eliminate all microorganisms. Surgical asepsis (sterile technique) is the practice that eliminates all microorganisms, including spores, from an object or area.",a:"B) False",r:"Asepsis"},
{id:118,s:"IC",t:"mc",q:"When should a nurse perform hand hygiene according to the WHO's 5 Moments? (Choose the INCORRECT option)",o:["Before patient contact","After body fluid exposure","Before charting at the nurses' station","After touching patient surroundings"],c:[2],e:"The 5 Moments of Hand Hygiene are: before patient contact, before an aseptic task, after body fluid exposure, after patient contact, and after touching patient surroundings. 'Before charting at the nurses' station' is not one of the 5 moments, though it is good practice.",a:"C) Before charting at the nurses' station",r:"Hand Hygiene"},
{id:119,s:"IC",t:"mc",q:"A nurse is applying sterile gloves. The first glove is placed on the dominant hand by:",o:["Grasping the outside of the glove cuff with the non-dominant hand","Grasping the inside folded cuff of the glove with the non-dominant hand","Having another nurse place the glove on","Using teeth to hold the glove open"],c:[1],e:"When applying the first sterile glove, the nurse picks it up by the inside folded cuff (which will touch the skin) with the non-dominant bare hand. This maintains sterility of the outer glove surface. The second glove is picked up by sliding the sterile gloved fingers under the cuff.",a:"B) Grasping the inside folded cuff of the glove with the non-dominant hand",r:"Sterile Gloving"},
{id:120,s:"IC",t:"mc",q:"The MOST effective way to reduce VAP in mechanically ventilated patients is:",o:["Keeping the patient flat in bed to prevent aspiration","Performing oral care with chlorhexidine every 2 hours and maintaining HOB elevation at 30-45 degrees","Suctioning the patient every 30 minutes","Using antibiotics prophylactically for all ventilated patients"],c:[1],e:"The VAP prevention bundle includes oral care with chlorhexidine every 2 hours and head of bed (HOB) elevation at 30-45 degrees. Keeping patients flat increases aspiration risk. Routine suctioning and prophylactic antibiotics are not evidence-based VAP prevention measures.",a:"B) Performing oral care with chlorhexidine every 2 hours and maintaining HOB elevation at 30-45 degrees",r:"VAP Prevention"},
{id:121,s:"IC",t:"tf",q:"True or False: A sterile field can be established and then covered with a sterile drape to be used later.",o:["True","False"],c:[1],e:"False. A sterile field should be used immediately after setup. Covering it and leaving it for later use risks contamination because the field is no longer under continuous observation. A new sterile field should be established each time a sterile procedure is performed.",a:"B) False",r:"Sterile Technique"},
{id:122,s:"IC",t:"mc",q:"Which type of healthcare-associated infection is MOST common?",o:["CLABSI (Central Line-Associated Bloodstream Infection)","SSI (Surgical Site Infection)","CAUTI (Catheter-Associated Urinary Tract Infection)","VAP (Ventilator-Associated Pneumonia)"],c:[2],e:"CAUTI is the most common type of HAI, accounting for approximately 30-40% of all healthcare-associated infections. Most CAUTIs are related to indwelling urinary catheters, which is why daily assessment of catheter necessity and prompt removal are crucial prevention strategies.",a:"C) CAUTI (Catheter-Associated Urinary Tract Infection)",r:"HAIs"},
{id:123,s:"IC",t:"mc",q:"A nurse is donning PPE to enter the room of a patient on full isolation (Contact + Airborne). The CORRECT donning order is:",o:["Gloves, gown, N95, eye protection","Hand hygiene, gown, N95 respirator, eye protection, gloves","N95, gloves, gown, eye protection","Eye protection, mask, gown, gloves, hand hygiene"],c:[1],e:"The correct donning order is always: Hand hygiene → Gown → Mask/N95 → Eye protection → Gloves. This ensures complete coverage with each layer properly applied. Gloves go last to cover gown cuffs. Remember: 'My Gown Goes on, Eyes Covered, Gloves Last.'",a:"B) Hand hygiene, gown, N95 respirator, eye protection, gloves",r:"PPE Donning"},
{id:124,s:"IC",t:"fib",q:"For C. difficile hand hygiene, remember the mnemonic '_____ it up' which reminds nurses to use soap and water only.",o:[],c:["SOAP"],e:"'SOAP it up' reminds nurses that Soap and water is the ONLY effective hand hygiene method for C. difficile. Alcohol-based hand sanitizers do not kill C. difficile spores. The mechanical action of washing with soap and water physically removes the spores.",a:"SOAP",r:"C. diff Mnemonic"},
{id:125,s:"IC",t:"mc",q:"Proper disposal of sharps includes:",o:["Recapping needles before placing in the sharps container","Placing sharps in a puncture-resistant container immediately after use without recapping","Breaking needles before disposal","Bending needles before placing in regular trash"],c:[1],e:"Sharps should be placed in a puncture-resistant sharps container immediately after use WITHOUT recapping, bending, or breaking. Recapping needles is a major cause of needlestick injuries. The single most important practice is never to recap used needles.",a:"B) Placing sharps in a puncture-resistant container immediately after use without recapping",r:"Sharps Safety"},
{id:126,s:"IC",t:"tf",q:"True or False: Recapping used needles is an acceptable practice if done with one hand using the scoop technique.",o:["True","False"],c:[1],e:"False. Current best practice and OSHA guidelines recommend NEVER recapping used needles. While the one-hand scoop technique exists for specific rare situations, the standard of care is to never recap and to immediately dispose of sharps in a puncture-resistant container.",a:"B) False",r:"Sharps Safety"},
{id:127,s:"IC",t:"mc",q:"A nurse is bathing a patient and notices a reddened area over the patient's sacrum. The nurse should:",o:["Massage the reddened area vigorously to improve circulation","Document the finding as a stage 1 pressure injury, reposition the patient, and notify the provider","Apply powder to keep the area dry","Ignore it since redness is normal after lying in bed"],c:[1],e:"A non-blanchable reddened area over a bony prominence is a stage 1 pressure injury. The nurse should document the finding, reposition the patient to relieve pressure, implement a turning schedule, and notify the provider. Massaging a reddened area can cause further tissue damage.",a:"B) Document the finding as a stage 1 pressure injury, reposition the patient, and notify the provider",r:"Hygiene & Skin Assessment"},
{id:128,s:"IC",t:"mc",q:"The nurse teaches a patient about proper respiratory hygiene. Which instruction is CORRECT?",o:["Cough into your hands so you can wash them later","Cover your cough with a tissue, dispose of it immediately, and wash your hands","Cough into the open air to disperse the droplets","Cover your cough only if you have been diagnosed with an infection"],c:[1],e:"Respiratory hygiene/cough etiquette includes covering coughs and sneezes with a tissue, immediately disposing of the tissue, and performing hand hygiene. This is a Standard Precaution applied to ALL patients and visitors, not just those with known infections.",a:"B) Cover your cough with a tissue, dispose of it immediately, and wash your hands",r:"Respiratory Hygiene"},
{id:129,s:"IC",t:"sata",q:"Which of the following are components of Standard Precautions? (Select all that apply)",o:["Hand hygiene","Use of PPE based on anticipated exposure","Respiratory hygiene/cough etiquette","Safe injection practices","Isolation of all patients in private rooms"],c:[0,1,2,3],e:"Standard Precautions include: hand hygiene, PPE use based on anticipated exposure, respiratory hygiene, safe injection practices, safe handling of contaminated equipment, and environmental cleaning. NOT all patients require private rooms — that is part of Transmission-Based Precautions.",a:"A, B, C, D",r:"Standard Precautions"},
{id:130,s:"IC",t:"mc",q:"A nurse is teaching a patient about preventing infection at home after hospital discharge. Which instruction is MOST important?",o:["Avoid all contact with other people for 2 weeks","Wash your hands frequently, especially before eating and after using the bathroom","Take antibiotics daily to prevent infection","Keep all windows closed to prevent airborne germs"],c:[1],e:"Frequent hand hygiene is the most important and practical infection prevention measure for patients at home. Hand washing before eating and after using the bathroom prevents the most common routes of transmission. Prophylactic antibiotics and isolation are not standard discharge instructions.",a:"B) Wash your hands frequently, especially before eating and after using the bathroom",r:"Discharge Education"},
// ——— SBAR & COMMUNICATION (Questions 131–180) ———
// --- General SBAR Knowledge (131–150) ---
{id:131,s:"SB",t:"mc",q:"In SBAR communication, what does the 'S' stand for?",o:["Safety","Situation","Symptoms","Standards"],c:[1],e:"The 'S' in SBAR stands for Situation — a brief statement of the current problem or reason for the communication. It answers the question: 'What is happening right now with this patient?' This is the opening of any SBAR report.",a:"B) Situation",r:"SBAR"},
{id:132,s:"SB",t:"mc",q:"In SBAR communication, what does the 'B' stand for?",o:["Baseline","Background","Breathing","Behavior"],c:[1],e:"The 'B' in SBAR stands for Background — relevant patient history and context that led to the current situation. This includes diagnoses, medications, allergies, recent procedures, and lab results that provide context for the current concern.",a:"B) Background",r:"SBAR"},
{id:133,s:"SB",t:"mc",q:"In SBAR communication, what does the 'A' stand for?",o:["Action","Assessment","Allergies","Approach"],c:[1],e:"The 'A' in SBAR stands for Assessment — the nurse's clinical evaluation of the situation. It answers: 'What do I think is going on?' This is where the nurse uses clinical judgment to identify the suspected problem based on the data gathered.",a:"B) Assessment",r:"SBAR"},
{id:134,s:"SB",t:"mc",q:"In SBAR communication, what does the 'R' stand for?",o:["Results","Referral","Recommendation","Report"],c:[2],e:"The 'R' in SBAR stands for Recommendation — what the nurse thinks should be done. It answers: 'What do I think we should do about it?' This may include requests for orders, tests, medications, or provider assessment of the patient.",a:"C) Recommendation",r:"SBAR"},
{id:135,s:"SB",t:"mc",q:"A nurse is calling the provider about a patient with a new onset of chest pain. Which is an example of the 'Situation' component of SBAR?",o:["'The patient had a cardiac catheterization yesterday.'","'I am calling about Mr. Smith in room 302 who is experiencing new onset chest pain.'","'I think the patient may be having a myocardial infarction.'","'I would like you to come evaluate the patient and order a 12-lead ECG.'"],c:[1],e:"The Situation is a clear, concise statement of what is happening right now. 'I am calling about Mr. Smith in room 302 who is experiencing new onset chest pain' identifies the patient, location, and current problem. The other options represent Background, Assessment, and Recommendation.",a:"B) 'I am calling about Mr. Smith in room 302 who is experiencing new onset chest pain.'",r:"SBAR Application"},
{id:136,s:"SB",t:"mc",q:"Which SBAR component includes the statement: 'The patient was admitted 2 days ago for pneumonia and has a history of COPD'?",o:["Situation","Background","Assessment","Recommendation"],c:[1],e:"This statement provides relevant history and context — the reason for admission and pertinent medical history. This is the Background component of SBAR, which answers: 'What led to this situation? What is the clinical context?'",a:"B) Background",r:"SBAR Application"},
{id:137,s:"SB",t:"mc",q:"A nurse states: 'I believe the patient is becoming septic based on the elevated temperature, increased heart rate, and low blood pressure.' This represents which SBAR component?",o:["Situation","Background","Assessment","Recommendation"],c:[2],e:"This statement reflects the nurse's clinical judgment about what is happening with the patient. 'I believe the patient is becoming septic' is the Assessment — the nurse's analysis of the data and clinical impression of the problem.",a:"C) Assessment",r:"SBAR Application"},
{id:138,s:"SB",t:"mc",q:"Which statement is an example of the Recommendation component of SBAR?",o:["'The patient's oxygen saturation is 88%.'","'The patient has a history of heart failure.'","'I think the patient is experiencing fluid overload.'","'I would recommend ordering a chest X-ray and increasing the oxygen to 4L via nasal cannula.'"],c:[3],e:"The Recommendation states what the nurse thinks should be done. Requesting a chest X-ray and oxygen increase represents a specific, actionable recommendation. The other statements represent data (Situation/Background) and clinical judgment (Assessment).",a:"D) 'I would recommend ordering a chest X-ray and increasing the oxygen to 4L via nasal cannula.'",r:"SBAR Application"},
{id:139,s:"SB",t:"fib",q:"SBAR stands for Situation, Background, Assessment, and ____.",o:[],c:["Recommendation"],e:"SBAR stands for Situation, Background, Assessment, and Recommendation. This standardized communication framework ensures clear, concise handoffs and provider communications. It originated in the military and was adopted by healthcare to improve patient safety.",a:"Recommendation",r:"SBAR"},
{id:140,s:"SB",t:"mc",q:"SBAR communication is MOST commonly used for which of the following?",o:["Charting patient assessments","Handoff reports, calling providers, and shift change communication","Writing care plans","Completing admission paperwork"],c:[1],e:"SBAR is the gold standard for structured communication during handoff reports (between nurses), calling healthcare providers about patient concerns, and shift change communication. It ensures critical information is conveyed clearly, reducing errors related to miscommunication.",a:"B) Handoff reports, calling providers, and shift change communication",r:"SBAR Use"},
{id:141,s:"SB",t:"mc",q:"A nurse receives a verbal order from a physician over the phone. Which action is ESSENTIAL?",o:["Accept the order and implement it immediately","Read back the order to the provider and verify for accuracy","Have the patient confirm the order","Write the order on a napkin and enter it in the chart later"],c:[1],e:"Read-back and verify is essential for all verbal and telephone orders. The nurse must write down the order, read it back to the provider, and receive confirmation that it is correct. This closed-loop communication prevents errors. Verbal orders should be reserved for emergencies.",a:"B) Read back the order to the provider and verify for accuracy",r:"Verbal Orders"},
{id:142,s:"SB",t:"mc",q:"Verbal orders should ideally be used in which situation?",o:["Whenever the provider is too busy to write the order","Only in emergency situations when the provider cannot write the order","Anytime the nurse wants to speed up care","When the nurse disagrees with the written order"],c:[1],e:"Verbal orders should be reserved for emergency situations when the provider is unable to enter the order themselves. Verbal orders carry a higher risk of miscommunication and error. They must be read back, verified, and signed by the provider as soon as possible.",a:"B) Only in emergency situations when the provider cannot write the order",r:"Verbal Orders"},
{id:143,s:"SB",t:"mc",q:"Which statement about incident reports is CORRECT?",o:["Incident reports should assign blame to the responsible party","Incident reports should be objective, factual, and free from blame","Incident reports are filed as part of the patient's medical chart","Incident reports are only completed for medication errors"],c:[1],e:"Incident reports (occurrence reports) must be factual, objective, and non-punitive. They document what happened without assigning blame. They are filed separately from the patient's medical record and are used for quality improvement, not punishment.",a:"B) Incident reports should be objective, factual, and free from blame",r:"Incident Reports"},
{id:144,s:"SB",t:"tf",q:"True or False: Incident reports should be referenced or documented in the patient's medical chart.",o:["True","False"],c:[1],e:"False. Incident reports are confidential quality improvement documents and should NEVER be referenced in the patient's medical chart. The facts of the event should be documented in the chart, but the existence of an incident report itself should not be mentioned.",a:"B) False",r:"Incident Reports"},
{id:145,s:"SB",t:"mc",q:"A patient falls in the hospital. Which documentation should appear in the patient's chart?",o:["'An incident report was filed regarding the patient's fall.'","'Patient found on the floor at 0800, oriented x3, no visible injuries, VS stable, provider notified.'","'The fall was caused by the wet floor that housekeeping failed to dry.'","'Patient fell due to nursing negligence.'"],c:[1],e:"The chart should contain objective, factual documentation of what happened: how the patient was found, their condition, vital signs, and who was notified. Never reference the incident report in the chart, and never assign blame or make subjective judgments in documentation.",a:"B) 'Patient found on the floor at 0800, oriented x3, no visible injuries, VS stable, provider notified.'",r:"Documentation & Incident Reports"},
{id:146,s:"SB",t:"mc",q:"During shift change handoff, the nurse uses SBAR to communicate about a patient who had a blood sugar of 48 mg/dL. Which statement represents the Assessment?",o:["'The patient's blood sugar is 48 mg/dL.'","'The patient has type 1 diabetes and received insulin 2 hours ago.'","'I believe the patient is experiencing hypoglycemia related to the recent insulin administration.'","'I recommend rechecking the blood sugar in 15 minutes and having juice at the bedside.'"],c:[2],e:"The Assessment is the nurse's clinical judgment: 'I believe the patient is experiencing hypoglycemia related to the recent insulin administration.' The blood sugar reading is the Situation, the diabetes history is Background, and the blood sugar recheck is the Recommendation.",a:"C) 'I believe the patient is experiencing hypoglycemia related to the recent insulin administration.'",r:"SBAR Application"},
{id:147,s:"SB",t:"sata",q:"Which of the following are appropriate uses of SBAR? (Select all that apply)",o:["Nurse-to-nurse handoff at shift change","Nurse calling a provider about a change in patient condition","Nurse transferring a patient to another unit","A nurse ordering lunch in the cafeteria","Nurse communicating a critical lab value"],c:[0,1,2,4],e:"SBAR is used for all clinical communication that involves patient information: shift handoffs, provider calls, unit transfers, and reporting critical values. Ordering lunch is personal communication that does not require a structured clinical framework.",a:"A, B, C, E",r:"SBAR Use"},
{id:148,s:"SB",t:"mc",q:"A nurse is preparing to call the provider. Which action should the nurse take BEFORE making the call?",o:["Call immediately without reviewing the chart — speed is most important","Gather relevant patient data including vitals, labs, allergies, current meds, and assessment findings","Have another nurse make the call instead","Wait for the provider to round on the unit"],c:[1],e:"Before calling a provider, the nurse should be prepared with all relevant data organized using SBAR format: current situation, background information (chart review, vitals, labs, meds, allergies), assessment, and a recommendation. Being prepared shows professionalism and improves communication efficiency.",a:"B) Gather relevant patient data including vitals, labs, allergies, current meds, and assessment findings",r:"SBAR Preparation"},
{id:149,s:"SB",t:"mc",q:"The primary purpose of standardized handoff communication (like SBAR) is to:",o:["Reduce the length of shift change","Improve patient safety by ensuring critical information is not missed","Satisfy hospital administration requirements","Reduce the amount of charting needed"],c:[1],e:"The primary purpose of SBAR and other standardized handoff tools is to improve patient safety. Communication failures are the leading cause of sentinel events and medical errors. Standardized handoffs ensure critical information is consistently and completely communicated.",a:"B) Improve patient safety by ensuring critical information is not missed",r:"Communication Safety"},
{id:150,s:"SB",t:"tf",q:"True or False: Communication failures are the leading root cause of sentinel events in healthcare.",o:["True","False"],c:[0],e:"True. According to The Joint Commission, communication failures are consistently identified as the leading root cause of sentinel events (unexpected deaths or serious injuries). This is why standardized communication tools like SBAR are critical for patient safety.",a:"A) True",r:"Communication Safety"},
// --- Triage & Prioritizing SBAR Questions (151–165) ---
{id:151,s:"SB",t:"mc",q:"A nurse has multiple patients with changes in condition. Which patient should the nurse call the provider about FIRST using SBAR?",o:["Patient requesting a sleep medication","Patient whose blood pressure dropped from 130/80 to 88/50 in the last hour","Patient asking about their discharge plan","Patient requesting a dietary change"],c:[1],e:"A significant blood pressure drop (from 130/80 to 88/50) indicates potential hemodynamic instability that could lead to shock. This is the most urgent finding requiring immediate provider notification using SBAR. The other situations are not time-sensitive.",a:"B) Patient whose blood pressure dropped from 130/80 to 88/50 in the last hour",r:"Triage & SBAR Priority"},
{id:152,s:"SB",t:"mc",q:"A nurse is receiving handoff report and the offgoing nurse skips the Assessment and Recommendation components of SBAR. The oncoming nurse should:",o:["Accept the report as given — the important information was covered","Ask the offgoing nurse for their assessment of each patient and any recommendations for the shift","Look up the information later in the chart","Assume everything is fine since nothing was mentioned"],c:[1],e:"A complete SBAR handoff includes all four components. The oncoming nurse should ask for the Assessment (what the offgoing nurse thinks is going on) and Recommendations (what needs to be done). Incomplete handoffs lead to missed priorities and potential patient harm.",a:"B) Ask the offgoing nurse for their assessment of each patient and any recommendations for the shift",r:"SBAR Handoff"},
{id:153,s:"SB",t:"mc",q:"A new graduate nurse is nervous about calling the provider at 2 AM about a patient concern. What is the BEST approach?",o:["Wait until morning rounds to discuss the concern","Write out the SBAR format before calling to organize thoughts and present information clearly","Have the charge nurse make all calls to avoid bothering the provider","Ask the patient to call the provider themselves"],c:[1],e:"Writing out the SBAR before calling helps organize thoughts and present information professionally and efficiently. Patient safety concerns should never be delayed until morning. Using SBAR helps new nurses communicate confidently and ensures no critical information is missed.",a:"B) Write out the SBAR format before calling to organize thoughts and present information clearly",r:"SBAR Communication Skills"},
{id:154,s:"SB",t:"mc",q:"During SBAR handoff, the nurse reports: 'Mrs. Johnson in room 210 is a 72-year-old with heart failure. Her weight is up 3 pounds from yesterday, she has 2+ pitting edema, and her lungs have crackles in the bases. I think she is retaining fluid. I recommend the provider be notified for possible diuretic adjustment.' Which part is the Situation?",o:["'Mrs. Johnson in room 210' — identifying the patient","'72-year-old with heart failure' — the diagnosis","'Weight up 3 pounds, 2+ pitting edema, crackles' — the findings","'I think she is retaining fluid' — the clinical judgment"],c:[0],e:"The Situation component identifies who the patient is and the immediate concern. In this case, identifying Mrs. Johnson in room 210 sets the scene. The diagnosis is Background, the findings support the Assessment, and the clinical judgment IS the Assessment.",a:"A) 'Mrs. Johnson in room 210' — identifying the patient",r:"SBAR Application"},
{id:155,s:"SB",t:"mc",q:"A nurse delegates vital signs to a UAP who reports back that the patient's heart rate is 142 bpm. The nurse's FIRST action should be:",o:["Tell the UAP to retake vitals in an hour","Immediately assess the patient and prepare to call the provider using SBAR","Document the finding and continue with other tasks","Ask the UAP to give the patient water"],c:[1],e:"A heart rate of 142 bpm is significantly tachycardic and requires immediate nurse assessment. After assessment, the nurse should use SBAR to communicate findings to the provider. Vital sign abnormalities reported by UAPs require prompt RN follow-up and clinical decision-making.",a:"B) Immediately assess the patient and prepare to call the provider using SBAR",r:"Triage & SBAR"},
{id:156,s:"SB",t:"mc",q:"A patient is being transferred from the ICU to a medical-surgical floor. Which communication tool should be used?",o:["A brief verbal summary of the patient's name and room number","A comprehensive SBAR handoff including current status, background, assessment, and recommendations","A text message to the receiving nurse","The receiving nurse can read the chart on their own"],c:[1],e:"Patient transfers between units require comprehensive SBAR handoff communication. This ensures the receiving nurse has all critical information including the patient's current status, relevant history, current assessment, and recommendations for ongoing care. This prevents information gaps.",a:"B) A comprehensive SBAR handoff including current status, background, assessment, and recommendations",r:"SBAR Transfer Communication"},
{id:157,s:"SB",t:"mc",q:"A nurse witnesses a medication error by a colleague. In addition to ensuring patient safety, the nurse should:",o:["Confront the colleague publicly to ensure accountability","File an incident report that is factual, objective, and blame-free","Ignore it to maintain professional relationships","Post about it on social media as a learning experience"],c:[1],e:"The nurse should ensure patient safety first, then file an incident report that objectively documents what happened. Incident reports should be factual and blame-free, used for quality improvement. Public confrontation, ignoring errors, and social media posting are all inappropriate and potentially harmful.",a:"B) File an incident report that is factual, objective, and blame-free",r:"Incident Reports"},
{id:158,s:"SB",t:"mc",q:"The charge nurse notices communication breakdowns during shift change. Which intervention would be MOST effective?",o:["Shortening shift change to 5 minutes to reduce time waste","Implementing a standardized SBAR handoff tool for all shift change reports","Allowing nurses to give handoff without any structure","Eliminating bedside handoff to save time"],c:[1],e:"Implementing a standardized SBAR handoff tool provides structure and consistency to shift change communication. Standardized tools reduce omissions, improve information transfer, and have been shown to reduce adverse events related to communication failures.",a:"B) Implementing a standardized SBAR handoff tool for all shift change reports",r:"Communication Improvement"},
{id:159,s:"SB",t:"mc",q:"A nurse is calling the provider about a patient with a critical potassium level of 6.8 mEq/L. Using SBAR, the Recommendation should include:",o:["'I'll just wait for you to decide what to do.'","'I recommend you order a stat ECG, cardiac monitoring, and consider IV calcium gluconate and insulin/dextrose for hyperkalemia treatment.'","'I'm not sure what to do — please help.'","'The patient should be discharged.'"],c:[1],e:"An effective Recommendation is specific and action-oriented. For critical hyperkalemia (K+ 6.8), the nurse should recommend an ECG, cardiac monitoring, and standard hyperkalemia treatments. This shows clinical competence and facilitates prompt intervention.",a:"B) 'I recommend you order a stat ECG, cardiac monitoring, and consider IV calcium gluconate and insulin/dextrose for hyperkalemia treatment.'",r:"SBAR Recommendation"},
{id:160,s:"SB",t:"sata",q:"Which of the following are principles of effective incident reporting? (Select all that apply)",o:["Document only objective facts about what happened","Assign blame to the responsible individual","File the report separately from the patient's medical record","Include opinions about why the error occurred","Complete the report in a timely manner"],c:[0,2,4],e:"Effective incident reports are: objective and factual (no blame or opinions), filed separately from the medical record, and completed in a timely manner while details are fresh. Assigning blame discourages reporting and does not improve safety culture.",a:"A, C, E",r:"Incident Reports"},
{id:161,s:"SB",t:"mc",q:"A nurse is calling the rapid response team. Using SBAR, which statement BEST represents the Situation?",o:["'The patient has a history of diabetes and kidney disease.'","'I am calling a rapid response for Mr. Garcia in room 415 who is unresponsive and not breathing normally.'","'I think the patient is in respiratory failure.'","'Please intubate the patient and transfer to the ICU.'"],c:[1],e:"The Situation is a clear, urgent statement of what is happening NOW. 'I am calling a rapid response for Mr. Garcia in room 415 who is unresponsive and not breathing normally' immediately conveys who, where, and what. The other statements represent Background, Assessment, and Recommendation.",a:"B) 'I am calling a rapid response for Mr. Garcia in room 415 who is unresponsive and not breathing normally.'",r:"SBAR in Emergencies"},
{id:162,s:"SB",t:"mc",q:"During bedside handoff, the offgoing nurse should include the patient in the communication by:",o:["Talking about the patient in the third person while they listen","Introducing the oncoming nurse, reviewing the plan of care, and allowing the patient to ask questions and clarify information","Asking the patient to leave the room during handoff","Giving handoff in medical jargon so the patient doesn't understand sensitive information"],c:[1],e:"Bedside handoff is patient-centered. The offgoing nurse should introduce the oncoming nurse, review the plan of care using understandable language, and invite the patient to participate, ask questions, and correct any inaccuracies. This improves safety and patient satisfaction.",a:"B) Introducing the oncoming nurse, reviewing the plan of care, and allowing the patient to ask questions and clarify information",r:"Bedside Handoff"},
{id:163,s:"SB",t:"tf",q:"True or False: SBAR was originally developed for use in the healthcare industry.",o:["True","False"],c:[1],e:"False. SBAR was originally developed by the United States Navy for use in nuclear submarine operations where clear, concise communication was critical for safety. It was later adopted by healthcare to standardize communication and reduce errors related to miscommunication.",a:"B) False",r:"SBAR History"},
{id:164,s:"SB",t:"mc",q:"Which is the MOST important reason for using read-back and verify with verbal orders?",o:["To document that the nurse received the order","To prevent miscommunication and medication errors","To slow down the ordering process","To create a legal record"],c:[1],e:"Read-back and verify ensures that what the nurse heard matches what the provider intended. This closed-loop communication technique is the most important safeguard against miscommunication and resulting medication errors, which could cause serious patient harm.",a:"B) To prevent miscommunication and medication errors",r:"Verbal Orders"},
{id:165,s:"SB",t:"mc",q:"A nurse is prioritizing calls to providers. Which patient situation should be reported FIRST?",o:["A patient requesting a laxative","A patient whose oxygen saturation dropped from 97% to 82%","A patient asking for a dietary consult","A patient who wants to know their lab results"],c:[1],e:"An oxygen saturation dropping from 97% to 82% represents a critical change indicating potential respiratory failure. This is a medical emergency requiring immediate provider notification using SBAR. The other situations are important but not time-sensitive or life-threatening.",a:"B) A patient whose oxygen saturation dropped from 97% to 82%",r:"Triage & SBAR Priority"},
// --- Complex SBAR Scenarios (166–180) ---
{id:166,s:"SB",t:"mc",q:"A nurse calls the provider and uses SBAR. The provider gives a verbal order that the nurse believes is unsafe. The nurse should:",o:["Follow the order since the provider has more authority","Question the order respectfully, state the concern, and request clarification","Refuse to follow the order and hang up","Follow the order but document personal disagreement"],c:[1],e:"Nurses have a professional and ethical duty to question orders they believe are unsafe. The nurse should respectfully state their concern and request clarification. If the order remains unchanged and still seems unsafe, the nurse should follow the chain of command to resolve the concern.",a:"B) Question the order respectfully, state the concern, and request clarification",r:"Safe Communication"},
{id:167,s:"SB",t:"mc",q:"A nurse gives SBAR handoff to the oncoming nurse about a patient with a chest tube. The oncoming nurse seems distracted and is checking their phone. The BEST action is:",o:["Continue the handoff and hope the nurse was listening","Stop and say, 'This is important patient safety information — I need your full attention for this handoff.'","Complete the handoff and send an email summary later","Report the nurse to the manager"],c:[1],e:"Patient safety depends on effective handoff communication. If the receiving nurse is distracted, the handing-off nurse should assertively but respectfully redirect attention. Incomplete handoff due to distraction is a safety hazard and a leading cause of adverse events.",a:"B) Stop and say, 'This is important patient safety information — I need your full attention for this handoff.'",r:"Effective Handoff Communication"},
{id:168,s:"SB",t:"order",q:"Place the components of an SBAR report to a provider in the correct order.",o:["Situation: State the patient, location, and current concern","Background: Provide relevant history, diagnoses, and current treatment","Assessment: State your clinical impression of the problem","Recommendation: State what you think should be done"],c:[0,1,2,3],e:"SBAR follows a specific sequence: Situation first (what's happening now), then Background (context and history), Assessment (clinical judgment), and Recommendation (proposed action). This structure ensures logical, complete communication that providers can quickly follow.",a:"Situation → Background → Assessment → Recommendation",r:"SBAR Order"},
{id:169,s:"SB",t:"mc",q:"A nurse completes an SBAR call to the provider about a deteriorating patient but the provider does not call back with orders within 15 minutes. The nurse should:",o:["Wait patiently — the provider is probably busy","Escalate the concern through the chain of command (charge nurse, supervisor, or rapid response)","Continue routine care and document that the provider was called","Accept that the provider is unavailable and try again tomorrow"],c:[1],e:"When a provider does not respond to an urgent concern, the nurse must escalate through the chain of command. Patient safety cannot wait. The nurse should contact the charge nurse, nursing supervisor, or activate a rapid response if the patient is deteriorating.",a:"B) Escalate the concern through the chain of command (charge nurse, supervisor, or rapid response)",r:"Chain of Command"},
{id:170,s:"SB",t:"mc",q:"A nurse documents in the chart: 'The patient was obviously lying about their pain level.' This documentation is PROBLEMATIC because:",o:["It is too short","It contains a subjective judgment rather than objective, factual documentation","It includes too much detail","It should have been in the incident report instead"],c:[1],e:"Documentation must be objective and factual. Stating the patient was 'obviously lying' is a subjective judgment that is inappropriate, potentially defamatory, and unprofessional. The nurse should document the patient's statements in quotes and objective assessment findings.",a:"B) It contains a subjective judgment rather than objective, factual documentation",r:"Documentation"},
{id:171,s:"SB",t:"mc",q:"A nurse is giving SBAR handoff and the receiving nurse asks, 'What do you think is going on with this patient?' The sending nurse should respond with:",o:["'I don't know — I just took vitals.'","Their clinical Assessment: 'Based on the elevated WBC, fever, and wound drainage, I believe the patient is developing a wound infection.'","'Just read the chart.'","'That's the doctor's job to figure out.'"],c:[1],e:"The Assessment component of SBAR is where the nurse shares their clinical judgment. Nurses are expected to analyze data and form clinical impressions. Providing a clear assessment demonstrates competence and ensures the receiving nurse understands the clinical priority for the patient.",a:"B) Their clinical Assessment: 'Based on the elevated WBC, fever, and wound drainage, I believe the patient is developing a wound infection.'",r:"SBAR Assessment"},
{id:172,s:"SB",t:"sata",q:"Which of the following should be included in a shift change SBAR handoff? (Select all that apply)",o:["Patient's name, age, and room number","Current diagnoses and relevant medical history","Current vital signs and recent changes in condition","Pending tests, procedures, and expected results","The nurse's personal opinion about the patient's personality"],c:[0,1,2,3],e:"A complete SBAR handoff includes patient identification, current diagnoses and history (Background), recent assessment findings and changes (Situation/Assessment), and pending items with recommendations. Personal opinions about the patient are not relevant to clinical communication.",a:"A, B, C, D",r:"SBAR Handoff Content"},
{id:173,s:"SB",t:"mc",q:"A nurse receives a verbal order for 'morphine 2 mg IV push now.' The read-back should be:",o:["'Okay, got it.'","'You want morphine. I'll give it.'","'I am reading back: morphine 2 milligrams, intravenous push, to be given now. Is that correct?'","'Morphine — sure.'"],c:[2],e:"A proper read-back includes the complete order repeated verbatim: drug name, dose, route, and timing, followed by a request for confirmation. This closed-loop communication ensures accuracy and prevents medication errors. Simply saying 'okay' does not verify understanding.",a:"C) 'I am reading back: morphine 2 milligrams, intravenous push, to be given now. Is that correct?'",r:"Verbal Orders & Read-Back"},
{id:174,s:"SB",t:"mc",q:"A patient's family member is angry and yelling at the nurse about perceived poor care. The BEST initial response is:",o:["Yell back to establish authority","Remain calm, use active listening, acknowledge the concern, and say 'I understand you are upset. Let me help address your concerns.'","Walk away and ignore the family member","Tell the family member they need to leave the hospital"],c:[1],e:"Therapeutic communication techniques include remaining calm, active listening, and acknowledging the person's feelings. De-escalation through empathy and a willingness to address concerns is the most effective and professional initial response to an angry family member.",a:"B) Remain calm, use active listening, acknowledge the concern, and say 'I understand you are upset. Let me help address your concerns.'",r:"Therapeutic Communication"},
{id:175,s:"SB",t:"mc",q:"A nurse makes a medication error and immediately recognizes it. The CORRECT sequence of actions is:",o:["Hide the error to avoid punishment, then monitor the patient","Assess the patient for adverse effects → Notify the provider → Implement any ordered interventions → Notify the charge nurse → Complete an incident report","Complete the incident report first, then check on the patient","Call the pharmacy to ask what to do"],c:[1],e:"Patient safety is the first priority. The nurse must: (1) Assess the patient for adverse effects, (2) Notify the provider immediately, (3) Implement ordered interventions, (4) Notify the charge nurse, and (5) Complete an incident report. Never hide an error — transparency is essential for patient safety.",a:"B) Assess the patient → Notify provider → Implement interventions → Notify charge nurse → Complete incident report",r:"Medication Error Response"},
{id:176,s:"SB",t:"order",q:"Place the following actions in the correct order after a medication error is discovered.",o:["Assess the patient for adverse effects","Notify the healthcare provider","Implement any provider-ordered interventions","Notify the charge nurse","Complete an incident report"],c:[0,1,2,3,4],e:"After discovering a medication error, the priority sequence is: patient assessment first (safety), then provider notification (medical management), implement ordered interventions, notify the charge nurse (administrative), and finally complete the incident report (documentation and quality improvement).",a:"Assess patient → Notify provider → Implement interventions → Notify charge nurse → Complete incident report",r:"Error Response Sequence"},
{id:177,s:"SB",t:"mc",q:"A nurse is documenting care in the electronic health record. Which entry is an example of PROPER documentation?",o:["'Patient seems upset and is probably non-compliant.'","'Patient states, \"I did not take my medication this morning because I felt dizzy.\" VS: BP 100/60, HR 92, patient educated on importance of medication adherence and notifying provider of side effects.'","'Patient is a difficult and demanding person.'","'Everything is fine today. No problems.'"],c:[1],e:"Proper documentation is objective, factual, and includes direct patient quotes, measurable data (vital signs), and nursing interventions. It avoids subjective judgments ('seems upset,' 'difficult') and vague statements ('everything is fine'). Specific, measurable documentation supports continuity of care.",a:"B) Patient states, 'I did not take my medication...' with objective data and interventions",r:"Documentation"},
{id:178,s:"SB",t:"sata",q:"Which of the following are elements of closed-loop communication? (Select all that apply)",o:["The sender delivers the message","The receiver acknowledges the message and repeats it back","The sender verifies the message was received correctly","The receiver interprets the message silently without responding","Both parties confirm shared understanding"],c:[0,1,2,4],e:"Closed-loop communication includes: sender delivers the message, receiver acknowledges and repeats back, sender verifies accuracy, and both confirm understanding. Silent interpretation without response breaks the loop and is how miscommunication occurs.",a:"A, B, C, E",r:"Closed-Loop Communication"},
{id:179,s:"SB",t:"mc",q:"A student nurse is learning SBAR. They practice by saying: 'Hi Dr. Lee, I'm calling about Mrs. Patel in 318 — she's having new shortness of breath. She was admitted yesterday for CHF exacerbation, currently on Lasix 40 mg IV BID. Her O2 sat has dropped to 89% on 2L, she has bilateral crackles, and she's anxious. I think she's fluid-overloaded and needs a higher level of diuresis. I'd like to request an order for a stat chest X-ray, increase O2, and possibly a Lasix bolus.' How many SBAR components did the student correctly include?",o:["1","2","3","4"],c:[3],e:"The student correctly included all four SBAR components: S — new shortness of breath in Mrs. Patel room 318; B — admitted for CHF, on Lasix; A — thinks she is fluid-overloaded; R — requests chest X-ray, O2 increase, and Lasix bolus. This is an excellent example of complete SBAR communication.",a:"D) 4",r:"SBAR Application"},
{id:180,s:"SB",t:"mc",q:"The Joint Commission identifies communication failures as the top contributor to which type of healthcare event?",o:["Minor inconveniences","Sentinel events (unexpected deaths or serious patient harm)","Scheduling conflicts","Budget overruns"],c:[1],e:"The Joint Commission consistently identifies communication failures as the leading root cause of sentinel events — unexpected occurrences involving death or serious physical or psychological harm. This underscores why SBAR and other structured communication tools are critical for patient safety.",a:"B) Sentinel events (unexpected deaths or serious patient harm)",r:"Communication & Patient Safety"}
];
export const QUESTIONS_INFECTION = R.map(q => ({...q, section: S[q.s], type: q.t, options: q.o || [], correct: q.c, explanation: q.e, correctAnswer: q.a, ref: q.r, stem: q.q}));
export const SECTIONS_INFECTION = Object.values(S);
